class _SQLSheetError(Exception):
    pass


class _SQLCell:
    def __init__(self, row, col, value=""):
        self.row = row
        self.col = col
        self.value = value


class _SQLWorksheet:
    def __init__(self, name):
        self.name = str(name)

    def _df(self):
        df = db.load_sheet_table(self.name)
        return df.copy() if df is not None else pd.DataFrame()

    def _save(self, df):
        db.save_sheet_table(self.name, df)

    def get_all_records(self):
        df = self._df()
        return df.fillna("").astype(object).to_dict("records")
    
    def get_all_values(self):
        df = self._df()
        if df.empty and len(df.columns) == 0:
            return []
        headers = list(df.columns)
        rows = df.fillna("").astype(str).values.tolist()
        return [headers] + rows
    
    def row_values(self, row):
        df = self._df()
        headers = list(df.columns)
        if row == 1:
            return headers
        idx = row - 2
        if idx < 0 or idx >= len(df):
            return []
        return ["" if pd.isna(v) else v for v in df.iloc[idx].tolist()]

    def col_values(self, col):
        df = self._df()
        headers = list(df.columns)
        if col < 1 or col > len(headers):
            return []
        name = headers[col - 1]
        return [name] + ["" if pd.isna(v) else v for v in df[name].tolist()]

    def append_row(self, values, value_input_option=None):
        self.append_rows([values], value_input_option=value_input_option)

    # Sheet columns backed by NOT NULL boolean DB columns (see QC1_*_COLS in
    # db.py). When a caller's append_row() list is shorter than the table
    # (e.g. it doesn't pass Is Voided/Label Printed), these must be padded
    # with "FALSE" rather than "" — an empty string round-trips through
    # db._clean_sql_value() as NULL, which overrides the column's own
    # DEFAULT and trips the NOT NULL constraint on insert.
    _BOOLEAN_FLAG_COLUMNS = {"Is Voided", "Label Printed"}

    def append_rows(self, rows, value_input_option=None):
        df = self._df()
        if df.empty and len(df.columns) == 0:
            max_len = max((len(r) for r in rows), default=0)
            df = pd.DataFrame(columns=[f"Column {i}" for i in range(1, max_len + 1)])
        cols = list(df.columns)
        for row in rows:
            while len(row) > len(cols):
                new_col = f"Column {len(cols) + 1}"
                df[new_col] = ""
                cols.append(new_col)
            fill = ["FALSE" if c in self._BOOLEAN_FLAG_COLUMNS else "" for c in cols[len(row):]]
            df.loc[len(df)] = list(row) + fill
        self._save(df)

    def clear(self):
        df = self._df()
        self._save(pd.DataFrame(columns=list(df.columns)))

    def update(self, *args, **kwargs):
        # Accept ANY call shape gspread-style code might use:
        #   update(values)
        #   update(range_name, values)
        #   update(range_name, values, value_input_option=...)
        #   update(values=..., value_input_option=...)
        # By taking *args/**kwargs instead of named params, this can never
        # raise "got multiple values for argument" regardless of how a call
        # site mixes positional and keyword arguments.
        kwargs.pop("value_input_option", None)  # no-op for SQL, just swallow it
        range_name = kwargs.pop("range_name", None)
        values = kwargs.pop("values", None)

        if len(args) == 1:
            if values is None:
                values = args[0]
        elif len(args) >= 2:
            if range_name is None:
                range_name = args[0]
            if values is None:
                values = args[1]

        if values is None and range_name is not None and not isinstance(range_name, str):
            values = range_name  # called as update(values) positionally

        if not values:
            self.clear()
            return
        headers = [str(h) for h in values[0]]
        rows = values[1:]
        normalized = [list(r) + [""] * (len(headers) - len(r)) for r in rows]
        self._save(pd.DataFrame(normalized, columns=headers))

    def update_cell(self, row, col, value):
        df = self._df()
        # SQL columns arrive with real dtypes (bool/int/date). This shim
        # emulates a text spreadsheet where any cell holds any value, so widen
        # to object before writing — otherwise assigning e.g. "TRUE" into a
        # bool column raises: Invalid value 'TRUE' for dtype 'bool'.
        df = df.astype(object)
        cols = list(df.columns)
        while col > len(cols):
            new_col = f"Column {len(cols) + 1}"
            df[new_col] = ""
            cols.append(new_col)
        if row == 1:
            old = cols[col - 1]
            df = df.rename(columns={old: str(value)})
            self._save(df)
            return
        if row - 2 >= len(df):
            # This call means "edit an existing row" — the row number was
            # resolved earlier against a cached snapshot that no longer
            # matches the live table (data changed since the page loaded).
            # Padding with a blank row would insert one with NULLs in
            # NOT NULL columns (e.g. the id PK) and crash anyway, so fail
            # clearly instead of writing a garbage row.
            raise _SQLSheetError(
                f"Row {row} no longer exists in '{self.name}' — the underlying "
                "data changed since this page was loaded. Please refresh and retry."
            )
        df.iat[row - 2, col - 1] = value
        self._save(df)

    def update_cells(self, cells, value_input_option=None):
        df = self._df()
        # SQL columns arrive with real dtypes (bool/int/date). This shim
        # emulates a text spreadsheet where any cell holds any value, so widen
        # to object before writing — otherwise assigning e.g. "TRUE" into a
        # bool column raises: Invalid value 'TRUE' for dtype 'bool'.
        df = df.astype(object)
        cols = list(df.columns)
        max_col = max((c.col for c in cells), default=len(cols))
        while max_col > len(cols):
            new_col = f"Column {len(cols) + 1}"
            df[new_col] = ""
            cols.append(new_col)
        max_row = max((c.row for c in cells), default=1)
        if max_row - 2 >= len(df):
            # See update_cell() above: an out-of-range row here means the
            # row number was resolved against a stale cached snapshot —
            # fail clearly instead of padding with a blank (NULL-filled) row.
            raise _SQLSheetError(
                f"Row {max_row} no longer exists in '{self.name}' — the underlying "
                "data changed since this page was loaded. Please refresh and retry."
            )
        for cell in cells:
            if cell.row == 1:
                old = cols[cell.col - 1]
                df = df.rename(columns={old: str(cell.value)})
                cols[cell.col - 1] = str(cell.value)
            else:
                df.iat[cell.row - 2, cell.col - 1] = cell.value
        self._save(df)

    def find(self, query, in_column=None):
        needle = str(query).strip()
        df = self._df().fillna("")
        columns = list(df.columns)
        search_cols = [columns[in_column - 1]] if in_column and 1 <= in_column <= len(columns) else columns
        for r_idx, row in df.iterrows():
            for col_name in search_cols:
                if str(row.get(col_name, "")).strip() == needle:
                    return _SQLCell(r_idx + 2, columns.index(col_name) + 1, row.get(col_name, ""))
        return None

    def delete_rows(self, row):
        df = self._df()
        idx = row - 2
        if 0 <= idx < len(df):
            df = df.drop(df.index[idx]).reset_index(drop=True)
            self._save(df)

    # ── Sheets-era grid API — no-ops on SQL (columns exist, rows unbounded) ──
    def resize(self, rows=None, cols=None):
        return None

    @property
    def row_count(self):
        return len(self._df()) + 1  # +1 to mimic the header row

    @property
    def col_count(self):
        return len(self._df().columns)


class _SQLWorkbook:
    def worksheet(self, name):
        return _SQLWorksheet(name)

    def add_worksheet(self, name, rows=1000, cols=20):
        return _SQLWorksheet(name)


class _SQLSpreadsheetClient:
    def open_by_key(self, key):
        return _SQLWorkbook()


