# NOTE: SQL worksheet compatibility, requests, and random are already imported above.
import time as _time_module  # rename to avoid clashing with any other 'time' usage

def with_backoff(func, *args, max_attempts=6, base_wait=2, label="", **kwargs):
    last_exc = None
    for attempt in range(max_attempts):
        try:
            return func(*args, **kwargs)
        except gspread.exceptions.APIError as api_err:
            last_exc = api_err
            status_code = 0
            try:
                status_code = api_err.response.status_code
            except Exception:
                pass
            if status_code == 429 and attempt < max_attempts - 1:
                wait = min(base_wait * (2 ** attempt), 60) + random.uniform(0, 3)
                try:
                    st.toast(
                        f"SQL backend is busy{' (' + label + ')' if label else ''}"
                        f" — retrying in {wait:.0f}s …",
                        icon="⏳"
                    )
                except Exception:
                    pass
                _time_module.sleep(wait)
                continue
            raise
        except (requests.exceptions.ReadTimeout,
                requests.exceptions.ConnectionError) as net_err:
            last_exc = net_err
            if attempt < max_attempts - 1:
                wait = base_wait * (2 ** attempt)
                try:
                    st.toast(
                        f"Network issue{' (' + label + ')' if label else ''}"
                        f" — retrying in {wait:.0f}s …",
                        icon="⏳"
                    )
                except Exception:
                    pass
                _time_module.sleep(wait)
                continue
            raise
    if last_exc:
        raise last_exc


def batch_update_cells(ws, row_idx, headers, updates):
    if not updates:
        return
    cells = []
    for col_name, value in updates.items():
        if col_name in headers:
            col_idx = headers.index(col_name) + 1
            cells.append(gspread.Cell(row_idx, col_idx, value))
        else:
            st.error(f"DEBUG batch_update: column '{col_name}' not in headers: {headers}")
            return
    if cells:
        try:
            ws.update_cells(cells, value_input_option="USER_ENTERED")
        except Exception as e:
            st.error(f"DEBUG[v2-patched] batch_update update_cells failed: {e} | row_idx={row_idx} | cells={[(c.row, c.col, c.value) for c in cells]}")
            raise

