def log_audit(action, category, detail, **kwargs):
    try:
        division = st.session_state.get("division", "")
        username = st.session_state.get("username", st.session_state.get("user_id", "unknown"))
        role = st.session_state.get("role", st.session_state.get("user_role", "unknown"))
        db.log_audit(division or "QC1", username, role, action, str(category), str(detail), **kwargs)
    except Exception:
        pass  # audit failure must never block the main user action

def confirm_submit(key, label="Save", button_type="primary", use_container_width=True):
    """
    Two-step confirmation that works inside st.dialog() without st.rerun().

    Streamlit dialogs re-render on every widget interaction automatically.
    We only need to toggle a session_state flag — no rerun required.

    Flow:
      Render 1: flag=False  → shows the primary button
      Render 2: flag=True   → shows warning + Yes / Cancel
      Render 3: Yes clicked → resets flag, returns True (caller saves data)
               Cancel       → resets flag, returns False
    """
    confirm_key = f"_confirm_{key}"

    if not st.session_state.get(confirm_key, False):
        # ── Stage 1: primary action button ───────────────────────────────
        if st.button(label, key=f"{key}_btn", type=button_type,
                     use_container_width=use_container_width):
            st.session_state[confirm_key] = True
            # No st.rerun() — the dialog will re-render on the next
            # Streamlit cycle because session_state changed.
        return False

    else:
        # ── Stage 2: confirmation ─────────────────────────────────────────
        st.warning(
            "⚠️ Are you sure you want to submit this? "
            "This action will be recorded and may not be reversible."
        )
        c1, c2 = st.columns(2)
        with c1:
            if st.button("✅ Yes, Submit", key=f"{key}_yes",
                         type="primary", use_container_width=True):
                st.session_state[confirm_key] = False
                return True
        with c2:
            if st.button("✖ Cancel", key=f"{key}_no",
                         use_container_width=True):
                st.session_state[confirm_key] = False
        return False

def show_correction_void_dialog(sheet_name: str, items: list, id_field: str, label_field: str, correctable_fields: list, key_suffix: str = ""):
    """
    Opens a dialog where user selects an item (from items list) and then chooses
    to correct a field or void the record. Reuses the existing correction/void forms.
    items: list of dicts with keys 'id' and 'label'
    """
    @st.dialog("💬 Comment / Correction / Void", width="medium")
    def _dialog():
        # Step 1: select item
        item_options = {item['label']: item['id'] for item in items}
        selected_label = st.selectbox("Select item", options=list(item_options.keys()), key=f"sel_{key_suffix}")
        if not selected_label:
            st.info("Please select an item.")
            return
        selected_id = item_options[selected_label]

        # Step 2: select action
        action = st.radio(
            "Action",
            ["✏️ Correct a field", "⛔ Void this record"],
            key=f"action_{key_suffix}",
            horizontal=True,
        )
        st.markdown("---")

        # Step 3: show appropriate form
        if action == "✏️ Correct a field":
            # We need to fetch current values for this record.
            # For reagents, we have a row; for standards, we need the group's first row; for cells, one row.
            # To avoid duplication, we call a small helper that returns current_values dict.
            current_values = _get_current_values_for_record(sheet_name, selected_id, correctable_fields)
            if current_values is None:
                st.error("Could not load current values.")
                return
            # Reuse the correction form (defined earlier)
            _render_correction_form(sheet_name, selected_id, selected_label, current_values, key_suffix + "_" + selected_id)
        else:  # void
            # For void, we need the id column name (usually "ID" or "Standard ID" or "Cell ID")
            id_col = "ID"  # Default, but we can pass as parameter
            if sheet_name.endswith("Standards"):
                id_col = "ID"  # Standards uses "ID" column
            elif sheet_name.endswith("CellCulture"):
                id_col = "Cell ID"
            else:
                id_col = "ID"
            _render_void_form(sheet_name, selected_id, id_col, selected_label, key_suffix + "_" + selected_id)

    _dialog()

def _get_current_values_for_record(sheet_name: str, record_id: str, fields: list) -> dict:
    """
    Fetch current values from the database for the given record ID.
    """
    from db import SHEET_TABLES, QC2_TABLE_MAP, QC2_COLUMN_MAP
    import pandas as pd

    # ---- 1. Determine SQL table and column mapping ----
    if sheet_name.startswith("QC2_"):
        sql_table = QC2_TABLE_MAP.get(sheet_name)
        if not sql_table:
            return None
        col_map = QC2_COLUMN_MAP.get(sql_table, {})
        sheet_id_col = "ID"
        db_id_col    = "id"
    else:
        table_info = SHEET_TABLES.get(sheet_name)
        if not table_info:
            return None
        sql_table, col_map = table_info

        if sheet_name.endswith("Standards"):
            sheet_id_col = "Standard ID"
            db_id_col    = col_map.get("Standard ID", "standard_id")
        elif sheet_name.endswith("CellCulture"):
            sheet_id_col = "Cell ID"
            db_id_col    = col_map.get("Cell ID", "cell_id")
        elif sheet_name.endswith("Units"):
            parts = record_id.split("|") if "|" in str(record_id) else [record_id, ""]
            if len(parts) == 2:
                reagent_id, unit_label = parts[0].strip(), parts[1].strip()
            else:
                return None
        else:
            sheet_id_col = "ID"
            db_id_col    = col_map.get("ID", "id")

    # ---- 2. Build and execute the query ----
    try:
        # Use db._get_conn() so we never close the shared connection
        conn = db._get_conn()
        db_fields = [col_map.get(f, f.lower().replace(" ", "_")) for f in fields]
        select_cols = ", ".join(db_fields)

        if sheet_name.endswith("Units") and 'reagent_id' in dir():
            query = f"SELECT {select_cols} FROM {sql_table} WHERE reagent_id = %s AND unit_label = %s"
            df = pd.read_sql(query, conn, params=(reagent_id, unit_label))
        else:
            query = f"SELECT {select_cols} FROM {sql_table} WHERE {db_id_col}::text = %s"
            df = pd.read_sql(query, conn, params=(str(record_id),))
        # NOTE: do NOT call conn.close() — it's a shared cached connection

        if df.empty:
            return None

        result = {}
        for sheet_field, db_field in zip(fields, db_fields):
            if db_field in df.columns:
                val = df.iloc[0][db_field]
                result[sheet_field] = str(val) if val is not None and str(val) != "None" else ""
            else:
                result[sheet_field] = ""
        return result

    except Exception as e:
        st.error(f"Error fetching record from database: {e}")
        return None

