def validate_password(pw):
    errors = []
    if len(pw) < 8:            errors.append("At least 8 characters")
    if not re.search(r'[A-Z]', pw): errors.append("At least one uppercase letter")
    if not re.search(r'[a-z]', pw): errors.append("At least one lowercase letter")
    if not re.search(r'\d',    pw): errors.append("At least one number")
    if not re.search(r'[^A-Za-z0-9]', pw): errors.append("At least one symbol")
    return errors

def decode_barcode_from_photo(photo_bytes):
    try:
        image = Image.open(io.BytesIO(photo_bytes))
        
        # Upscale small images so pyzbar can read them
        w, h = image.size
        if w < 800:
            scale = 800 / w
            image = image.resize((int(w * scale), int(h * scale)), Image.LANCZOS)
        
        # Convert to grayscale and boost contrast
        image = image.convert("L")  # grayscale
        from PIL import ImageEnhance, ImageFilter
        image = ImageEnhance.Contrast(image).enhance(2.0)
        image = image.filter(ImageFilter.SHARPEN)
        
        barcodes = decode(image)
        if barcodes:
            return barcodes[0].data.decode('utf-8')
        return None
    except Exception:
        return None

def upload_to_supabase(file_bytes, file_name, bucket="reagent-docs"):
    """
    Uploads a file to Supabase Storage and returns the public URL.
    The bucket must exist and be public.
    """
    try:
        supabase = get_supabase()
        import uuid
        ext = file_name.split('.')[-1] if '.' in file_name else 'pdf'
        unique_name = f"{uuid.uuid4().hex}_{file_name}"
        file_path = unique_name

        with st.spinner("Uploading to Supabase..."):
            response = supabase.storage.from_(bucket).upload(
                path=file_path,
                file=file_bytes,
                file_options={"content-type": "application/pdf"}
            )

        if hasattr(response, 'error') and response.error:
            st.error(f"Upload error: {response.error}")
            return None

        public_url = supabase.storage.from_(bucket).get_public_url(file_path)
        return public_url

    except Exception as e:
        st.error(f"Upload failed: {str(e)}")
        return None

MAX_UPLOAD_SIZE_BYTES = 1024 * 1024  # 1 MB — Supabase Storage bucket limit

def oversized_file_error(**files):
    """
    Check named uploaded files (Streamlit UploadedFile objects) against
    MAX_UPLOAD_SIZE_BYTES. Returns an error message naming the first
    oversized file and its size, or None if all files are within limit.
    Call this BEFORE any upload/save is attempted so an oversized file
    blocks the whole save instead of silently saving without it.
    """
    for label, f in files.items():
        if f is not None and getattr(f, "size", 0) > MAX_UPLOAD_SIZE_BYTES:
            size_mb = f.size / (1024 * 1024)
            return (
                f"{label} is {size_mb:.2f} MB — files must be 1 MB or smaller. "
                "Remove it or upload a smaller file before saving."
            )
    return None

