def _draw_bi_label_60x35(c, bi_name, control_no, lot_no, receipt_date, expiry_date, form_info, barcode_text=""):
    """
    Low-level reportlab drawer for the Biological Indicator Label, sized
    exactly 60mm x 35mm, with a QR code column on the right using the SAME
    column ratio as _draw_ss_label_60x35() (22mm label / 22mm value /
    16mm QR). The BI Name (Control No.) field auto-shrinks, and wraps to
    2 lines if it's still too long, so it can never overflow into the
    row above again.
    """
    from reportlab.lib.utils import ImageReader
    from reportlab.pdfbase.pdfmetrics import stringWidth

    W, H = 60 * mm, 35 * mm

    def X(v): return v * mm
    def Y(top_mm): return H - top_mm * mm

    def ctr(cx, top, text, font, size):
        c.setFont(font, size)
        c.drawCentredString(X(cx), Y(top), str(text))

    def lft(x, top, text, font, size):
        c.setFont(font, size)
        c.drawString(X(x), Y(top), str(text))

    def rgt(x, top, text, font, size):
        c.setFont(font, size)
        c.drawRightString(X(x), Y(top), str(text))

    def wrap_line(text, font, size, max_w_mm):
        words = text.split(" ")
        lines, cur = [], ""
        for w in words:
            trial = (cur + " " + w).strip()
            if stringWidth(trial, font, size) <= max_w_mm * mm or not cur:
                cur = trial
            else:
                lines.append(cur)
                cur = w
        if cur:
            lines.append(cur)
        return lines

    title_h = 7.0
    row1_bottom = 14.0
    row2_bottom = 19.5
    row3_bottom = 25.5
    row4_bottom = 31.5
    col_x = 22.0
    qr_x = 44.0

    c.setLineWidth(0.5)
    c.rect(0, 0, W, H)
    c.line(0, Y(title_h), W, Y(title_h))
    c.line(0, Y(row1_bottom), X(qr_x), Y(row1_bottom))
    c.line(0, Y(row2_bottom), X(qr_x), Y(row2_bottom))
    c.line(0, Y(row3_bottom), X(qr_x), Y(row3_bottom))
    c.line(0, Y(row4_bottom), W, Y(row4_bottom))
    c.line(X(col_x), Y(title_h), X(col_x), Y(row4_bottom))
    c.line(X(qr_x), Y(title_h), X(qr_x), Y(row4_bottom))

    ctr(30, 4.2, "Label Indikator Biologi", "Helvetica-Bold", 7.0)
    ctr(30, 6.2, "Biological Indicator Label", "Helvetica-Oblique", 5.0)

    ctr(11, 10.4, "Nama BI (No. Control)", "Helvetica-Bold", 4.0)
    ctr(11, 12.4, "BI Name (Control No.)", "Helvetica-Oblique", 3.7)

    # ── BI Name (Control No.) — auto-fit, wraps to 2 lines if too long ──
    name_full = f"{bi_name} ({control_no})"
    value_w_mm = 20.0  # usable width inside the 22mm value column
    font_bold = "Helvetica-Bold"
    fitted_size = next(
        (sz for sz in (5.6, 5.0, 4.4) if stringWidth(name_full, font_bold, sz) <= value_w_mm * mm),
        None
    )
    if fitted_size:
        ctr(33, 11.9, name_full, font_bold, fitted_size)
    else:
        wrap_size = 4.2
        lines = wrap_line(name_full, font_bold, wrap_size, value_w_mm)
        if len(lines) > 2:
            wrap_size = 3.6
            lines = wrap_line(name_full, font_bold, wrap_size, value_w_mm)[:2]
        if len(lines) == 1:
            ctr(33, 11.9, lines[0], font_bold, wrap_size)
        else:
            ctr(33, 10.3, lines[0], font_bold, wrap_size)
            ctr(33, 13.2, lines[1], font_bold, wrap_size)

    ctr(11, 16.3, "No. Lot", "Helvetica-Bold", 4.0)
    ctr(11, 18.3, "Lot No.", "Helvetica-Oblique", 3.7)
    ctr(33, 17.7, str(lot_no), "Helvetica", 5.6)

    ctr(11, 22.3, "Tanggal Penerimaan", "Helvetica-Bold", 4.0)
    ctr(11, 24.3, "Date of Receipt", "Helvetica-Oblique", 3.7)
    ctr(33, 23.7, str(receipt_date), "Helvetica", 5.6)

    ctr(11, 28.3, "Tanggal Kedaluwarsa", "Helvetica-Bold", 4.0)
    ctr(11, 30.3, "Expiry Date", "Helvetica-Oblique", 3.7)
    ctr(33, 29.7, str(expiry_date), "Helvetica", 5.6)

    lft(1.5, 34.2, f"Form info.: {form_info}", "Helvetica", 4.2)
    rgt(58.5, 34.2, "CONFIDENTIAL", "Helvetica-BoldOblique", 4.4)

    # ── QR code column ──
    qr_zone_top, qr_zone_bottom = title_h, row4_bottom
    qr_zone_h = qr_zone_bottom - qr_zone_top
    qsz = min(14.0, qr_zone_h - 1.5) * mm
    qr_center_top = (qr_zone_top + qr_zone_bottom) / 2
    qr_cx = (qr_x + 60) / 2
    try:
        qr = qrcode.QRCode(version=1,
                           error_correction=qrcode.constants.ERROR_CORRECT_M,
                           box_size=10, border=2)
        qr.add_data(barcode_text or control_no)
        qr.make(fit=True)
        qimg = qr.make_image(fill_color="black", back_color="white").convert("RGB")
        qx = X(qr_x) + (X(60) - X(qr_x) - qsz) / 2
        qy = Y(qr_center_top) - qsz / 2
        c.drawImage(ImageReader(qimg), qx, qy, qsz, qsz)
    except Exception:
        c.setFont("Helvetica", 5)
        c.drawCentredString(X(qr_cx), Y(qr_center_top), "QR ERR")


def generate_bi_label_pdf_bytes(bi_name, control_no, lot_no, receipt_date, expiry_date,
                                 total_box=1, barcode_list=None, form_info="SQC01-011-A01 (Ver. 1.0)"):
    """
    PDF version of the Biological Indicator Label. Page size exactly
    60mm x 35mm, zero margins, one page per box (matches Box Label
    generation logic), each page now carrying its own QR code.
    """
    from io import BytesIO
    from reportlab.pdfgen import canvas

    total_box = max(1, int(total_box or 1))
    if not barcode_list:
        barcode_list = [control_no] * total_box

    buf = BytesIO()
    c = canvas.Canvas(buf, pagesize=(60 * mm, 35 * mm))

    for bc in barcode_list:
        _draw_bi_label_60x35(
            c, bi_name=bi_name, control_no=control_no, lot_no=lot_no,
            receipt_date=receipt_date, expiry_date=expiry_date,
            form_info=form_info, barcode_text=bc
        )
        c.showPage()

    c.save()
    return buf.getvalue()


def generate_pack_label_compact_pdf(nama, kode, batch, exp, tgl, pack_list,
                                    form_info="SQC01-007-A03 (Ver. 3.0)"):
    """
    PDF version of the Pack Label using the EXACT SAME 60x35mm layout as
    generate_label_box_compact_pdf() (same table structure, fonts, spacing,
    title style, QR placement, footer) via the shared _draw_media_label_60x35()
    helper. The only difference is the extra info around the QR code:
    "Pack X of Y" above it and "Box A of B" below it.
    pack_list items are the dicts produced by generate_pack_barcodes()
    (expects Barcode_Unique, Pack_Number, Box_Number). Returns PDF bytes
    (one page per pack).
    """
    from io import BytesIO
    from reportlab.pdfgen import canvas

    if isinstance(pack_list, dict):
        pack_list = [pack_list]

    total_packs = len(pack_list)
    total_boxes = max((int(p.get('Box_Number', 1)) for p in pack_list), default=1)

    buf = BytesIO()
    c = canvas.Canvas(buf, pagesize=(60 * mm, 35 * mm))

    for p in pack_list:
        pack_num = p.get('Pack_Number', 1)
        box_num = p.get('Box_Number', 1)
        barcode_text = p.get('Barcode_Unique', '')
        _draw_media_label_60x35(
            c, kode=kode, tgl=tgl, batch=batch, exp=exp,
            form_info=form_info, barcode_text=barcode_text,
            qr_top_text=f"Pack {pack_num} of {total_packs}",
            qr_bottom_text=f"Box {box_num} of {total_boxes}"
        )
        c.showPage()

    c.save()
    return buf.getvalue()


