def get_label_pending_set(context_key):
    sk = f"label_pending_{context_key}"
    if sk not in st.session_state:
        st.session_state[sk] = set()
    return st.session_state[sk]

def mark_label_pending(context_key, ids):
    s = get_label_pending_set(context_key)
    if isinstance(ids, (list, set, tuple)):
        s.update(str(i) for i in ids)
    else:
        s.add(str(ids))

def clear_label_pending(context_key, ids=None):
    s = get_label_pending_set(context_key)
    if ids is None:
        s.clear()
    else:
        for i in (ids if isinstance(ids, (list, set, tuple)) else [ids]):
            s.discard(str(i))

def _mark_label_downloaded():
    """download_button on_click — fires ONLY on a real download click (not on
    every rerun), so this is the correct point at which a label counts as
    "printed". Marks the persistent label_printed flag for whatever was
    generated (stored in `label_download_action`), then invalidates the reagent
    cache so the label dropdowns re-query fresh on their next open."""
    action = st.session_state.get("label_download_action")
    if not action:
        return
    division = st.session_state.get("division", "QC1")
    try:
        kind = action.get("kind")
        if kind == "reagent":
            for rid in action.get("ids", []):
                db.mark_reagent_label_printed(rid)
        elif kind == "opened_reagent":
            for rid in action.get("ids", []):
                db.mark_opened_unit_labels_printed(division, rid)
        elif kind == "unit":
            db.mark_unit_label_printed(
                division, action.get("reagent_id"), action.get("unit_label")
            )
        elif kind == "cell_culture":
            for cid in action.get("ids", []):
                db.mark_cell_culture_label_printed(cid)
    except Exception:
        pass
    # Mirror reagent_page._rgt_invalidate() (not in scope from this module-level
    # callback) so the just-marked record disappears from the dropdowns.
    st.session_state["rgt_cache_valid"] = False
    for _k in list(st.session_state.keys()):
        if _k.startswith("rgt_cache_time_") or _k.startswith("rgt_unit_rows_"):
            st.session_state.pop(_k, None)


def show_label_expander():
    pdf_bytes = st.session_state.get("reagent_label_pdf_bytes")
    if not pdf_bytes:
        return
    name = st.session_state.get("reagent_label_name", "Reagent")
    qty = st.session_state.get("reagent_label_qty", 1)
    pending_key = st.session_state.get("reagent_label_pending_key")
    pending_ids = st.session_state.get("reagent_label_pending_ids")

    with st.expander(f"🖨️ Labels ready — {name}  ({qty} unit{'s' if qty != 1 else ''})", expanded=True):
        st.caption(f"{name} — {qty} label{'s' if qty != 1 else ''} ready as a PDF.")

        safe_name = re.sub(r'[^A-Za-z0-9_-]+', '_', name).strip('_') or "reagent"
        st.download_button(
            "⬇️ Download Label PDF",
            data=pdf_bytes,
            file_name=f"{safe_name}_labels.pdf",
            mime="application/pdf",
            key="download_reagent_labels",
            on_click=_mark_label_downloaded,   # mark printed only on real download
            use_container_width=True,
        )
        st.caption(
            "Open the downloaded PDF and print it, selecting the "
            "\"ZDesigner ZT411-203dpi ZPL\" printer, the pre-configured "
            "60×35mm custom paper size, and scale set to \"Actual size / 100%\" "
            "(never \"Fit to page\")."
        )

        if st.button("✕ Dismiss", key="dismiss_reagent_labels", use_container_width=True):
            if pending_key and pending_ids:
                clear_label_pending(pending_key, pending_ids)
            for k in ("reagent_label_pdf_bytes","reagent_label_name","reagent_label_qty",
                      "reagent_label_pending_key","reagent_label_pending_ids",
                      "label_download_action"):
                st.session_state.pop(k, None)
            st.rerun()
