def generate_unique_barcodes(mgmt_code, qty):
    """
    Return `qty` QR text strings for a given Management Code — one per
    box/copy, but all identical, since the QR represents the Management
    Code only (not an individual physical box/pack). Used by every Print
    Label tab (Media, Reagent, BI, Standard Strain) and Register Arrival.
    """
    qty = max(1, int(qty or 1))
    code = str(mgmt_code).strip() or "CODE"
    return [code] * qty


def generate_pack_barcodes(mgmt_code, batch, total_packs, packs_per_box):
    shared_barcode = str(mgmt_code)
    records = []
    box_num = 1
    for i in range(1, total_packs + 1):
        pack_in_box = ((i - 1) % packs_per_box) + 1
        if i > 1 and pack_in_box == 1:
            box_num += 1
        records.append({
            "Barcode_Unique": shared_barcode,
            "Management_Code": mgmt_code,
            "Batch": batch,
            "Type": "Pack",
            "Pack_Number": i,
            "Pack_In_Box": f"{pack_in_box} of {packs_per_box}",
            "Box_Number": box_num,
            "Status": "Available"
        })
    return records

def generate_inventory_id():
    """Buat ID unik untuk setiap item di Master_Inventory."""
    import uuid
    return str(uuid.uuid4())[:8].upper()

def add_to_master_inventory(category, mgmt_code, item_name, batch_lot, arrival_date, exp_date, qty_in, status, pic, ghs, storage_temp, manufacturer, coa, msds):
    # QC2 master inventory function
    df_master = load_data("Master_Inventory")
    new_row = pd.DataFrame([{
        "Inventory_ID": str(uuid.uuid4())[:8].upper(),
        "Category": category,
        "Management_Code": mgmt_code,
        "Item_Name": item_name,
        "Batch_Lot": batch_lot,
        "Arrival_Date": arrival_date,
        "Expired_Date": exp_date,
        "Qty_In": qty_in,
        "Qty_Out": 0,
        "Stock": qty_in,
        "Status": status,
        "PIC": pic,
        "GHS": ghs,
        "Storage_Temp": storage_temp,
        "Manufacturer": manufacturer,
        "CoA": coa,
        "MSDS": msds
    }])
    df_master = pd.concat([df_master, new_row], ignore_index=True)
    save_data(df_master, "Master_Inventory")
    return new_row["Inventory_ID"].values[0]

