def login(username, password, division):
    try:
        users_df = get_users_sheet()
        users_df.columns = [c.strip() for c in users_df.columns]
        users_df["Username"] = users_df["Username"].astype(str).str.strip()
        row = users_df[users_df["Username"] == username.strip()]
        if row.empty:
            return False, "Username not found."
        r = row.iloc[0]
        status = str(r.get("Status", "")).strip().lower()
        if status == "pending":
            return False, "Your account is pending approval."
        elif status == "inactive":
            return False, "Your account has been deactivated."
        elif status == "on leave":
            return False, "Your account is currently on leave. Contact QA to have it reactivated."
        elif str(r.get("Password", "")).strip() != password:
            return False, "Incorrect password."
        # Check 90-day expiry
        last_act = str(r.get("Last Activated At", "")).strip()
        approved_at = str(r.get("Approved At", "")).strip()
        ref_date_str = last_act if last_act else approved_at
        expired = False
        try:
            ref_dt = pd.to_datetime(ref_date_str)
            if (datetime.now() - ref_dt).days > 90:
                expired = True
        except Exception:
            pass
        if expired:
            return False, "Your account has expired (90 days). Please contact QA."
        # Check division matches the one selected on login
        user_division = str(r.get("Division", "")).strip()
        if user_division != division:
            return False, f"Your account is registered for {user_division}, but you selected {division}. Please choose the correct division."
        st.session_state.logged_in = True
        st.session_state.username = username.strip()
        st.session_state.role = str(r.get("Role", "")).strip().lower()
        st.session_state.division = division
        st.session_state.full_name = str(r.get("Full Name", "")).strip()
        # QC2 reference pages expect these aliases; keep the original keys for QC1.
        st.session_state.user_id = st.session_state.username
        st.session_state.user_role = st.session_state.role
        st.session_state.user_name = st.session_state.full_name or st.session_state.username
        st.session_state.menu = "🏠 Dashboard" if division == "QC2" else "Dashboard"
        log_audit("LOGIN", "Authentication",
                  f"User logged in: {st.session_state.username} ({st.session_state.role}) — {division}")
        return True, "Login successful."
    except Exception as e:
        return False, f"Login error: {e}"
    
def validate_username(username: str, full_name: str = "") -> list:
    """
    Username rules for Selatox employees:
    - Must be your personal initial (as assigned by Selatox)
    - Exactly 3 uppercase letters
    - No numbers, spaces, or special characters
    """
    errors = []
    username = username.strip()

    if not username:
        errors.append("Username is required.")
        return errors

    if not re.match(r'^[A-Z]{3}$', username):
        errors.append("Username must be exactly 3 uppercase letters (your Selatox initial, e.g. ESP, NDA, RFI).")

    return errors
def register_user(username, full_name, password, division):
    try:
        users_df = db.load_users()
        users_df["Username"] = users_df["Username"].astype(str).str.strip()
        if username.strip() in users_df["Username"].values:
            return False, "Username already exists."
        db.insert_user(username.strip(), full_name.strip(), password, "", division)
        log_audit("REGISTER USER", "User Management",
                  f"New account registered (pending approval): {username.strip()} "
                  f"({full_name.strip()}) — {division}")
        return True, "Registration submitted! Please wait for QA approval."
    except Exception as e:
        return False, f"Registration error: {e}"

def show_login_page():
    st.markdown("""
    <style>
        header[data-testid="stHeader"] { display: none; }
        .block-container { padding-top: 2rem; }
        #MainMenu {visibility:hidden;} footer {visibility:hidden;}
    </style>""", unsafe_allow_html=True)

    col_l, col_c, col_r = st.columns([1, 1.4, 1])
    with col_c:
        try:
            logo = Image.open("selatox_logo.png")
            st.image(logo, width=160)
        except Exception:
            st.markdown("### SELATOX")
        st.markdown("#### QC Laboratory Management System")
        st.markdown("---")

        tab_login, tab_register = st.tabs(["Login", "Register"])

        with tab_login:
            username_input = st.text_input("Username", key="li_username")
            password_input = st.text_input("Password", type="password", key="li_password")
            division_input = st.selectbox("Division", ["QC1", "QC2"], key="li_division")
            if st.button("Log in", use_container_width=True, type="primary", key="li_btn"):
                if not username_input or not password_input:
                    st.warning("Please enter username and password.")
                else:
                    success, msg = login(username_input, password_input, division_input)
                    if success:
                        st.rerun()
                    else:
                        st.error(msg)

        with tab_register:
            st.caption("New accounts require QA approval before they can be used.")
            reg_fullname = st.text_input("Full Name *", key="reg_fullname")
            reg_username = st.text_input("Username *", key="reg_username")
            reg_division = st.selectbox("Division *", ["QC1", "QC2"], key="reg_division")
            reg_password = st.text_input("Password *", type="password", key="reg_password")
            reg_confirm = st.text_input("Confirm Password *", type="password", key="reg_confirm")

            if reg_password:
                errors = validate_password(reg_password)
                if errors:
                    for e in errors:
                        st.markdown(f'<span style="color:#EF4444;font-size:12px;">✗ {e}</span>',
                                    unsafe_allow_html=True)
                else:
                    st.markdown('<span style="color:#22C55E;font-size:12px;">✓ Password meets all requirements</span>',
                                unsafe_allow_html=True)

            st.caption("💡 Username must be your Selatox employee initial (exactly 3 uppercase letters, e.g. ESP, NDA, RFI).")

            if reg_username:
                username_errors = validate_username(reg_username, reg_fullname)
                if username_errors:
                    for e in username_errors:
                        st.markdown(
                            f'<span style="color:#EF4444;font-size:12px;">✗ {e}</span>',
                            unsafe_allow_html=True
                        )
                else:
                    st.markdown(
                        '<span style="color:#22C55E;font-size:12px;">✓ Username is valid</span>',
                        unsafe_allow_html=True
                    )

            if st.button("Register", use_container_width=True, type="primary", key="reg_btn"):
                if not all([reg_fullname, reg_username, reg_password, reg_confirm]):
                    st.error("All fields are required.")
                elif validate_username(reg_username, reg_fullname):
                    for e in validate_username(reg_username, reg_fullname):
                        st.error(e)
                elif reg_password != reg_confirm:
                    st.error("Passwords do not match.")
                elif validate_password(reg_password):
                    st.error("Password does not meet requirements.")
                else:
                    success, msg = register_user(
                        reg_username.upper(), reg_fullname,
                        reg_password, reg_division
                    )
                    if success:
                        st.success(msg)
                    else:
                        st.error(msg)

