def qc2_sheet_name(sheet_name):
    name = str(sheet_name).strip()
    if name.startswith("QC2_"):
        return name
    if st.session_state.get("division") == "QC2" and name in QC2_BASE_SHEETS:
        return f"QC2_{name}"
    return name

def load_data(sheet_name):
    """Load a logical QC2 worksheet from Supabase, preserving sheet-era columns."""
    actual_sheet = qc2_sheet_name(sheet_name)
    try:
        df = db.load_sheet_table(actual_sheet)
    except Exception as e:
        st.warning(f"Error loading data '{actual_sheet}': {e}")
        df = pd.DataFrame(columns=QC2_COLUMN_STANDARDS.get(actual_sheet, []))
    if actual_sheet in QC2_COLUMN_STANDARDS:
        for col in QC2_COLUMN_STANDARDS[actual_sheet]:
            if col not in df.columns:
                df[col] = "-"
        order = QC2_COLUMN_STANDARDS[actual_sheet] + [c for c in df.columns if c not in QC2_COLUMN_STANDARDS[actual_sheet]]
        df = df[order]
    return df

@st.cache_data(ttl=30, show_spinner=False)
def load_data_cached(sheet_name):
    """
    Cached wrapper around load_data() for read-only display data.
    30s safety-net TTL, but in practice it's invalidated immediately by
    save_data() (which already clears the cache on every write), so this
    only prevents *redundant* re-fetches between saves — e.g. every
    rerun caused by clicking, typing, or switching tabs.
    Do NOT use this right before a save (read-modify-write) — use
    load_data() or read_fresh() there instead, to avoid overwriting a
    concurrent change with stale data.
    """
    return load_data(sheet_name)

def _clear_qc2_cache(*sheet_names):
    """Scoped cache invalidation for the sheet(s) actually affected, instead
    of st.cache_data.clear() (which wipes every cached table for the whole
    app — every other QC2 page's next render would then re-fetch all of its
    data from Supabase too, even sheets this save/read never touched). Only
    load_data_cached's own 30s-TTL entries are cleared here; other
    @st.cache_data-decorated helpers elsewhere in the app are unaffected
    either way, exactly as before."""
    for name in sheet_names:
        try:
            load_data_cached.clear(name)
        except Exception:
            pass

def save_data(df, sheet_name, audit_action=None, audit_detail=None):
    """Save a logical QC2 worksheet to Supabase, preserving sheet-era columns."""
    actual_sheet = qc2_sheet_name(sheet_name)
    if df is None:
        df = pd.DataFrame(columns=QC2_COLUMN_STANDARDS.get(actual_sheet, []))
    ok = db.save_sheet_table(actual_sheet, df)
    if not ok:
        st.error(f"❌ Save failed: '{actual_sheet}' has no matching database table. Data was NOT saved.")
        return False
    _clear_qc2_cache(sheet_name, actual_sheet)
    if audit_action:
        log_audit(audit_action, actual_sheet, audit_detail or f"Saved {len(df)} rows")
    return True

def read_fresh(sheet_name):
    """Always read directly from Google Sheets bypassing cache — use before any save."""
    try:
        st.cache_data.clear()
        df = db.load_sheet_table(qc2_sheet_name(sheet_name))
        if df.empty:
            return pd.DataFrame()
        return df.dropna(how='all')
    except Exception as e:
        st.warning(f"Could not read fresh data from '{sheet_name}': {e}")
        return pd.DataFrame()
    
def safe_parse_date(val):
    if pd.isna(val) or val in [None, '', '-']:
        return pd.NaT
    val_str = str(val).strip()
    for fmt in ['%d/%m/%Y', '%Y-%m-%d', '%d-%m-%Y', '%d %b %Y', '%d %B %Y']:
        try:
            return pd.to_datetime(val_str, format=fmt)
        except:
            continue
    return pd.to_datetime(val_str, errors='coerce')

def safe_int(val, default=0):
    try:
        if pd.isna(val) or str(val).strip() in ['', '-', 'nan', 'None']:
            return default
        return int(float(str(val).strip()))
    except:
        return default

def safe_float(val, default=0.0):
    """Convert any value to float, falling back to `default` for blanks, '-', or anything unparseable."""
    if val is None:
        return default
    s = str(val).strip()
    if s in ('', '-', 'nan', 'None', 'NaT'):
        return default
    try:
        return float(s)
    except (ValueError, TypeError):
        return default

def clean_lot(val):
    if val is None:
        return '-'
    s = str(val).strip()
    if s in ['', 'nan', 'None', 'NaT', '-']:
        return '-'
    if s.endswith('.0'):
        prefix = s[:-2]
        if prefix.lstrip('-').isdigit():
            return prefix
    return s
