def has_permission(permission: str) -> bool:
    """Check if current user has a specific permission."""
    role = st.session_state.get('user_role', 'guest').strip().lower()
    role_map = {k.lower(): v for k, v in ROLE_PERMISSIONS.items()}
    return role_map.get(role, {}).get(permission, False)

def _permission_for_role(role: str, permission: str) -> bool:
    """Look up whether a given role grants a given permission (role passed explicitly)."""
    role_map = {k.lower(): v for k, v in ROLE_PERMISSIONS.items()}
    return role_map.get(str(role).strip().lower(), {}).get(permission, False)

# ─────────────────────────────────────────────────────────────────────────
# TEMPORARY ROLE DELEGATION (QC1 + QC2)
# ─────────────────────────────────────────────────────────────────────────
# A delegation lets an Owner User temporarily hand their approval authority
# to a Delegate User for a date range, without ever changing either user's
# stored role/ROLE_PERMISSIONS lookup. Status (Pending/Active/Expired) is
# always computed from dates — never stored — so nothing needs a manual
# "expire" step; only Revoked is a real, persisted flag.

def _to_plain_date(val):
    """Normalize a DB/date_input value (str, date, datetime, pandas
    Timestamp, or None) down to a plain datetime.date, or None."""
    if val is None:
        return None
    if isinstance(val, datetime):
        return val.date()
    if isinstance(val, date):
        return val
    parsed = safe_parse_date(val)
    return parsed.date() if pd.notna(parsed) else None


def _compute_delegation_status(row, today=None) -> str:
    """Pending / Active / Expired / Revoked, purely derived from dates."""
    today = today or date.today()
    if bool(row.get('is_revoked')):
        return "Revoked"
    start = _to_plain_date(row.get('start_date'))
    end = _to_plain_date(row.get('end_date'))
    if start is not None and today < start:
        return "Pending"
    if end is not None and today > end:
        return "Expired"
    return "Active"


def get_active_delegation_as_delegate(username: str = None, division: str = None):
    """The delegation (dict) currently granting `username` delegated approval
    authority right now in `division` (default: the logged-in user/division),
    or None."""
    username = username or st.session_state.get('username')
    division = division or st.session_state.get('division')
    if not username or not division:
        return None
    try:
        return db.get_active_delegation_for_delegate(username, division=division)
    except Exception:
        return None


def get_delegations_for_owner(owner_username: str, division: str = None) -> pd.DataFrame:
    division = division or st.session_state.get('division')
    try:
        return db.get_delegations_for_owner(owner_username, division=division)
    except Exception:
        return pd.DataFrame()


def _validate_delegation_overlap(owner_username: str, start_date, end_date, division: str, exclude_id=None) -> bool:
    """True if [start_date, end_date] doesn't overlap any existing
    non-revoked delegation already on record for this owner."""
    existing = get_delegations_for_owner(owner_username, division=division)
    if existing.empty:
        return True
    for _, row in existing.iterrows():
        if exclude_id is not None and str(row.get('id')) == str(exclude_id):
            continue
        row_start = _to_plain_date(row.get('start_date'))
        row_end = _to_plain_date(row.get('end_date'))
        if row_start is None or row_end is None:
            continue
        if start_date <= row_end and end_date >= row_start:
            return False
    return True


def has_permission_or_delegated(permission: str) -> bool:
    """Like has_permission(), but also grants the permission if the current
    user is an Active Delegate standing in for someone whose original role
    grants it. Native permission always wins first — a delegation can only
    ever add access, never take it away."""
    if has_permission(permission):
        return True
    deleg = st.session_state.get('_active_deleg_as_delegate')
    if not deleg:
        return False
    return _permission_for_role(deleg.get('owner_role_snapshot', ''), permission)


def get_delegation_audit_context(permission: str, module_label: str):
    """None if `permission` is held natively (nothing to attach to the audit
    log — caller's log_audit() stays exactly as it is today); otherwise a
    dict of kwargs to splat into log_audit(...) recording who this action
    was really performed for."""
    if has_permission(permission):
        return None
    deleg = st.session_state.get('_active_deleg_as_delegate')
    if not deleg:
        return None
    return {
        "acting_for_username": deleg.get('owner_username', ''),
        "delegation_status": "Active",
        "module": module_label,
    }


def _gatekeeper_coverage_warning(users_df, username, division):
    """
    Check whether `username` is currently the ONLY Active user in `division`
    holding a 'gatekeeper' permission (approve GPT/arrival tests, or manage
    users). Returns a list of human-readable warnings to show a QA admin
    before they deactivate or set this user on leave.
    """
    gatekeeper_perms = {
        "can_approve_gpt":  "approve GPT / arrival test results",
        "can_manage_users": "manage users",
    }
    active_same_div = users_df[
        (users_df["Status"].str.strip().str.lower() == "active") &
        (users_df["Division"].str.strip() == division)
    ]
    warnings = []
    for perm, label in gatekeeper_perms.items():
        holders = [
            u for u in active_same_div["Username"]
            if _permission_for_role(
                active_same_div.loc[active_same_div["Username"] == u, "Role"].iloc[0],
                perm
            )
        ]
        if holders == [username]:
            warnings.append(
                f"⚠️ **{username}** is the only active user in **{division}** who can {label}. "
                f"No one else will be able to do this until they return or another user is promoted."
            )
    return warnings

def permission_denied():
    """Show access denied message."""
    st.warning("🔒 Access restricted. You don't have permission for this action.")

def render_void_amendment(sheet_name, id_col, id_options, category_label):
    """
    Reusable Void + Amendment expander for any table-based module.
    - sheet_name: Google Sheets worksheet name
    - id_col: column name used to identify the row (e.g. 'Batch', 'Management Code')
    - id_options: list of values to show in the selectbox
    - category_label: label for audit log (e.g. 'Media', 'BI', 'Standard Strain')
    """
    if not id_options:
        return

    with st.expander("🔴 Void / Amendment", expanded=False):
        if not has_permission("can_delete"):
            st.warning("🔒 Void/Amendment restricted to QA and Admin only.")
            return

        st.caption(
            "This will keep the original row and add a new corrected row. "
            "Both rows remain visible in the table for full traceability."
        )

        selected_id = st.selectbox(
            f"Select {id_col} to Void/Amend",
            id_options,
            key=f"void_select_{sheet_name}"
        )

        void_reason = st.text_area(
            "Reason for Void / Amendment (required)",
            placeholder="e.g. Wrong batch number entered. Correct batch is B2024-002.",
            key=f"void_reason_{sheet_name}"
        )

        col_v1, col_v2 = st.columns(2)
        void_only = col_v1.checkbox(
            "Void only (no correction needed)",
            key=f"void_only_{sheet_name}"
        )

        correction_data = {}
        if not void_only:
            st.write("**Corrected Values** (leave blank to keep original):")
            col_c1, col_c2 = st.columns(2)
            correction_data['Corrected_Batch'] = col_c1.text_input(
                "Corrected Batch / Lot",
                key=f"void_batch_{sheet_name}"
            )
            correction_data['Corrected_Qty'] = col_c2.text_input(
                "Corrected Qty",
                key=f"void_qty_{sheet_name}"
            )
            correction_data['Corrected_Notes'] = st.text_input(
                "Corrected Notes",
                key=f"void_notes_{sheet_name}"
            )

        if st.button(
            "✅ Submit Void/Amendment",
            key=f"void_submit_{sheet_name}",
            type="primary"
        ):
            if not void_reason.strip():
                st.error("❌ Reason is required before submitting.")
                return

            df_current = read_fresh(sheet_name)
            if df_current.empty:
                st.error("Could not load data. Please try again.")
                return

            # Find the original row
            mask = df_current[id_col].astype(str).str.strip() == str(selected_id).strip()
            if not mask.any():
                st.error(f"Row with {id_col} = '{selected_id}' not found.")
                return

            original_idx = df_current[mask].index[0]
            original_row = df_current.loc[original_idx].to_dict()

            # Step 1 — Mark original row as VOIDED
            df_current.at[original_idx, 'Status'] = 'VOIDED'
            if 'Void_Reason' not in df_current.columns:
                df_current['Void_Reason'] = '-'
            if 'Void_By' not in df_current.columns:
                df_current['Void_By'] = '-'
            if 'Void_Date' not in df_current.columns:
                df_current['Void_Date'] = '-'
            df_current.at[original_idx, 'Void_Reason'] = void_reason.strip()
            df_current.at[original_idx, 'Void_By'] = st.session_state.user_name
            df_current.at[original_idx, 'Void_Date'] = datetime.now().strftime('%d %b %Y %H:%M').upper()

            # Step 2 — Add amendment row if correction provided
            if not void_only:
                amendment_row = original_row.copy()
                amendment_row['Status'] = 'AMENDED'
                amendment_row['Void_Reason'] = f"AMENDMENT of {selected_id}: {void_reason.strip()}"
                amendment_row['Void_By'] = st.session_state.user_name
                amendment_row['Void_Date'] = datetime.now().strftime('%d %b %Y %H:%M').upper()

                # Apply corrections if filled
                if correction_data.get('Corrected_Batch', '').strip():
                    for col in ['Batch', 'Lot', 'Catalog_Number']:
                        if col in amendment_row:
                            amendment_row[col] = correction_data['Corrected_Batch'].strip()
                if correction_data.get('Corrected_Qty', '').strip():
                    for col in ['Qty In (Pcs)', 'Quantity', 'Total_Pcs_Stock']:
                        if col in amendment_row:
                            try:
                                amendment_row[col] = int(correction_data['Corrected_Qty'].strip())
                            except:
                                pass
                if correction_data.get('Corrected_Notes', '').strip():
                    if 'Keterangan' in amendment_row:
                        amendment_row['Keterangan'] = correction_data['Corrected_Notes'].strip()

                df_current = pd.concat(
                    [df_current, pd.DataFrame([amendment_row])],
                    ignore_index=True
                )

            if save_data(df_current, sheet_name):
                action = "VOID" if void_only else "VOID+AMENDMENT"
                log_audit(
                    action, category_label,
                    f"{id_col}: {selected_id} | Reason: {void_reason} | By: {st.session_state.user_name}"
                )
                if void_only:
                    st.success(f"✅ {selected_id} marked as VOIDED.")
                else:
                    st.success(f"✅ {selected_id} voided and amendment row added.")
                st.rerun()
# ══════════════════════════════════════════════════════════════════════════════
# SHARED MONITORING LOGIC
# Used identically by both dashboard_page() and planning_page().
# Place this function ABOVE both page functions in your main file.
# ══════════════════════════════════════════════════════════════════════════════

def compute_monitoring_data(division):
    """
    Loads all inventory data and returns a single dict with expiry and
    low-stock results for Reagents, Standards, and Cell Culture.

    This is the SINGLE SOURCE OF TRUTH used by both the Dashboard and the
    Planning page. Any change to monitoring logic happens here only.

    Returns:
    {
        "reagents": {
            "expired":       [...],   # list of entry dicts
            "expiring_soon": [...],
            "critical":      [...],   # list of mgmt_code strings
            "warning":       [...],
            "summary":       {...},   # mgmt_code → info dict
        },
        "standards": {
            "expired":       [...],
            "expiring_soon": [...],
            "critical":      [...],   # list of rid strings
            "warning":       [...],
            "summary":       {...},
        },
        "cell_culture": {
            "critical":      [...],
            "warning":       [...],
        },
    }
    """
    from datetime import date, timedelta
    import pandas as pd

    today = date.today()

    # ── Loaders ───────────────────────────────────────────────────────────────
    def _load_reagents():
        try:
            df = db.load_reagents(division)
            if df.empty:
                return pd.DataFrame()
            if "ID" in df.columns:
                df["ID"] = df["ID"].astype(str).str.strip()
            if "Expiration Date" in df.columns:
                df["Expiration Date"] = pd.to_datetime(df["Expiration Date"], errors="coerce")
            for col in ["Reagent Name", "Management Code", "Lot Number",
                        "Manufacturer", "Catalog Number", "Arrival Qty"]:
                if col not in df.columns:
                    df[col] = ""
            return df
        except Exception:
            return pd.DataFrame()

    def _load_units():
        try:
            df = db.load_units(division)
            if df.empty:
                return pd.DataFrame()
            if "Box ID"    in df.columns: df.rename(columns={"Box ID":   "Reagent ID"}, inplace=True)
            if "Unit #"    in df.columns: df.rename(columns={"Unit #":   "Unit Label"}, inplace=True)
            if "Reagent ID" in df.columns: df["Reagent ID"] = df["Reagent ID"].astype(str).str.strip()
            if "Status"    in df.columns: df["Status"] = df["Status"].str.strip().str.lower()
            if "PAO" in df.columns:
                df["PAO (days)"] = df["PAO"].apply(
                    lambda x: parse_pao_to_days(str(x)) if pd.notna(x) and str(x).strip() else 0
                )
            else:
                df["PAO (days)"] = 0
            for col in ["Opened Date", "Disposed Date"]:
                if col in df.columns:
                    df[col] = pd.to_datetime(df[col], errors="coerce")
            # Normalise: all "unopened" variants → 'unused', keep 'opened'/'disposed'
            def _norm(s):
                s = str(s).strip().lower()
                if s in ("unused", "unopened", "available"):
                    return "unused"
                return s
            df["Status"] = df["Status"].apply(_norm)
            return df
        except Exception:
            return pd.DataFrame()

    def _load_standards():
        try:
            df = db.load_standards(division)
            if df.empty:
                return pd.DataFrame()
            for col in ["ID", "Standard ID"]:
                if col in df.columns:
                    df[col] = df[col].astype(str).str.strip()
            if "Expiry Date" in df.columns:
                df["Expiration Date"] = pd.to_datetime(df["Expiry Date"], errors="coerce")
            elif "Expiration Date" in df.columns:
                df["Expiration Date"] = pd.to_datetime(df["Expiration Date"], errors="coerce")
            # Rename so standards look like reagents to shared logic
            if "Standard ID" in df.columns and "ID" not in df.columns:
                df = df.rename(columns={"Standard ID": "ID"})
            if "Item Name" in df.columns and "Reagent Name" not in df.columns:
                df = df.rename(columns={"Item Name": "Reagent Name"})
            for col in ["Management Code", "Lot Number", "Manufacturer",
                        "Catalog Number", "Arrival Qty", "Stock Qty"]:
                if col not in df.columns:
                    df[col] = ""
            # Exclude voided
            if "Is Voided" in df.columns:
                df = df[df["Is Voided"].astype(str).str.upper() != "TRUE"].copy()
            return df
        except Exception:
            return pd.DataFrame()

    def _load_reorder_points():
        # Per-reagent low-stock thresholds live in Supabase (qc1lowstockpoints),
        # not the old {division}_LowStockPoints sheet. db.load_low_stock_points()
        # returns the exact {mgmt_code: {"warning":.., "critical":..}} shape the
        # threshold comparison below expects. The old gspread call always failed
        # into {} — so no reagent was ever flagged against its own threshold.
        try:
            return db.load_low_stock_points(division)
        except Exception:
            return {}

    def _load_cell_culture():
        try:
            return db.load_cell_culture(division)
        except Exception:
            return pd.DataFrame()

    # ── Load ──────────────────────────────────────────────────────────────────
    reagents_df    = _load_reagents()
    units_df       = _load_units()
    standards_df   = _load_standards()
    reorder_points = _load_reorder_points()
    cell_df        = _load_cell_culture()

    # Exclude voided reagents
    if not reagents_df.empty and "Is Voided" in reagents_df.columns:
        reagents_df = reagents_df[
            reagents_df["Is Voided"].astype(str).str.upper() != "TRUE"
        ].copy()

    # Exclude units belonging to voided reagents
    if not units_df.empty and not reagents_df.empty:
        valid_rids = set(reagents_df["ID"].astype(str))
        units_df = units_df[units_df["Reagent ID"].astype(str).isin(valid_rids)].copy()

    # Exclude individually-voided units — is_voided is independent of Status
    # (a voided unit keeps its unused/opened/disposed status), so it needs
    # its own exclusion on top of the reagent-level one above.
    if not units_df.empty and "Is Voided" in units_df.columns:
        units_df = units_df[units_df["Is Voided"].astype(str).str.upper() != "TRUE"].copy()

    result = {
        "reagents":     {"expired": [], "expiring_soon": [], "critical": [], "warning": [], "summary": {}},
        "standards":    {"expired": [], "expiring_soon": [], "critical": [], "warning": [], "summary": {}},
        "cell_culture": {"critical": [], "warning": []},
    }

    # ══════════════════════════════════════════════════════════════════════════
    # REAGENTS
    # ══════════════════════════════════════════════════════════════════════════
    if not reagents_df.empty and not units_df.empty:

        # -- Expiry monitoring --
        # For each unit: if unopened → use catalogue expiry; if opened → use EAO (PAO-based)
        # Only units that are NOT disposed and NOT in the local disposed_units set
        active_units = units_df[units_df["Status"] != "disposed"].copy()

        for _, reagent in reagents_df.iterrows():
            rid         = str(reagent["ID"])
            r_units     = active_units[active_units["Reagent ID"] == rid]
            cat_expiry  = reagent.get("Expiration Date")

            for _, unit in r_units.iterrows():
                status = str(unit.get("Status", "unused")).lower()
                label  = unit.get("Unit Label", "")

                if status == "unused":
                    # Unopened: use catalogue expiry
                    exp_date = cat_expiry
                elif status == "opened":
                    # Opened: use EAO = open date + PAO days; fall back to catalogue expiry
                    open_date = unit.get("Opened Date")
                    pao       = unit.get("PAO (days)", 0)
                    if pd.notna(open_date) and pao and pao > 0:
                        exp_date = pd.Timestamp(open_date) + timedelta(days=int(pao))
                    else:
                        exp_date = cat_expiry
                else:
                    continue

                if pd.isna(exp_date):
                    continue

                exp_d     = exp_date.date() if hasattr(exp_date, "date") else pd.to_datetime(exp_date).date()
                days_left = (exp_d - today).days

                entry = {
                    "Reagent Name":    reagent.get("Reagent Name", ""),
                    "Management Code": reagent.get("Management Code", ""),
                    "Lot Number":      reagent.get("Lot Number", ""),
                    "Unit":            label,
                    "Status":          "Opened" if status == "opened" else "Unopened",
                    "Expiry Date":     exp_d.strftime("%d %b %Y"),
                    "Days Left":       days_left,
                }
                if days_left < 0:
                    result["reagents"]["expired"].append(entry)
                elif days_left <= 30:
                    result["reagents"]["expiring_soon"].append(entry)

        result["reagents"]["expired"].sort(key=lambda x: x["Days Left"])
        result["reagents"]["expiring_soon"].sort(key=lambda x: x["Days Left"])

        # -- Low stock --
        # Group by Management Code, sum unopened counts across all lot entries
        # has_expired: only True if a reagent still has REMAINING unopened units
        # whose catalogue expiry has passed (not old cleared lots)
        mgmt_summary = {}

        for _, reagent in reagents_df.iterrows():
            rid  = str(reagent["ID"])
            mgmt = str(reagent.get("Management Code", "")).strip()
            if not mgmt:
                continue

            r_active   = active_units[active_units["Reagent ID"] == rid]
            unopened_n = int((r_active["Status"] == "unused").sum())

            # Expiry flag: only if there are still unopened units AND catalogue is expired
            has_expired_this = False
            if unopened_n > 0:
                cat_exp = reagent.get("Expiration Date")
                if pd.notna(cat_exp) and cat_exp.date() < today:
                    has_expired_this = True

            if mgmt not in mgmt_summary:
                mgmt_summary[mgmt] = {
                    "name":         str(reagent.get("Reagent Name", "")),
                    "manufacturer": str(reagent.get("Manufacturer", "")),
                    "catalog":      str(reagent.get("Catalog Number", "")),
                    "unopened":     0,
                    "has_expired":  False,
                }
            mgmt_summary[mgmt]["unopened"] += unopened_n
            if unopened_n > 0:
                mgmt_summary[mgmt]["has_expired"] = (
                    mgmt_summary[mgmt]["has_expired"] or has_expired_this
                )

        critical_list, warning_list = [], []
        if reorder_points:
            for mgmt, info in mgmt_summary.items():
                rp = reorder_points.get(mgmt)
                if rp is None:
                    continue
                stock    = info["unopened"]
                warn_thr = rp["warning"]
                crit_thr = rp["critical"]

                # Low-stock is purely a QUANTITY judgement vs this reagent's own
                # thresholds. Expiry is tracked separately (expired / expiring_soon
                # lists above); it must NOT force a well-stocked reagent into the
                # critical low-stock list — e.g. R-A-L-0002 with 10 unopened units
                # (one expired lot) is not low on stock.
                if stock <= crit_thr:
                    critical_list.append(mgmt)
                elif stock <= warn_thr:
                    warning_list.append(mgmt)

        result["reagents"]["critical"] = critical_list
        result["reagents"]["warning"]  = warning_list
        result["reagents"]["summary"]  = {
            mgmt: {
                "name":        info["name"],
                "mgmt_code":   mgmt,
                "manufacturer":info["manufacturer"],
                "catalog":     info["catalog"],
                "unopened":    info["unopened"],
                "has_expired": info["has_expired"],
            }
            for mgmt, info in mgmt_summary.items()
        }

    # ══════════════════════════════════════════════════════════════════════════
    # STANDARDS
    # ══════════════════════════════════════════════════════════════════════════
    if not standards_df.empty:

        # Standards use EAO from the Usage sheet (Opened Date + PAO).
        # For units that are "used" (opened), try to get EAO from the Standards sheet itself
        # (the EAO column written during usage registration).
        # For units that are "unused", use catalogue expiry date.

        for sid, grp in standards_df.groupby("ID"):
            sample = grp.iloc[0]
            cat_exp = sample.get("Expiration Date")
            mgmt    = str(sample.get("Management Code", "")).strip()

            for _, unit in grp.iterrows():
                status = str(unit.get("Status", "unused")).strip().lower()
                label  = unit.get("Aliquot Serial", unit.get("Serial Number", ""))

                if status == "disposed":
                    continue

                if status == "used":
                    # Use EAO if available, fall back to catalogue
                    eao_raw  = unit.get("EAO", "")
                    eao_date = pd.to_datetime(eao_raw, errors="coerce") if eao_raw else pd.NaT
                    exp_date = eao_date if pd.notna(eao_date) else cat_exp
                else:
                    # unused — catalogue expiry
                    exp_date = cat_exp

                if pd.isna(exp_date):
                    continue

                exp_d     = exp_date.date() if hasattr(exp_date, "date") else pd.to_datetime(exp_date).date()
                days_left = (exp_d - today).days

                entry = {
                    "Item Name":       sample.get("Reagent Name", ""),
                    "Management Code": mgmt,
                    "Lot Number":      sample.get("Lot Number", ""),
                    "Unit":            label,
                    "Status":          "Used" if status == "used" else "Unused",
                    "Expiry Date":     exp_d.strftime("%d %b %Y"),
                    "Days Left":       days_left,
                }
                if days_left < 0:
                    result["standards"]["expired"].append(entry)
                elif days_left <= 30:
                    result["standards"]["expiring_soon"].append(entry)

        result["standards"]["expired"].sort(key=lambda x: x["Days Left"])
        result["standards"]["expiring_soon"].sort(key=lambda x: x["Days Left"])

        # Standards low stock — percentage thresholds
        # Fall back to the simpler standards_df format used in planning page
        # (one row per Standard ID = one item, with Stock Qty and Arrival Qty)
        processed_sids = set()
        critical_list, warning_list = [], []
        std_summary = {}

        for sid, grp in standards_df.groupby("ID"):
            if str(sid) in processed_sids:
                continue
            processed_sids.add(str(sid))

            sample      = grp.iloc[0]
            mgmt        = str(sample.get("Management Code", "")).strip()
            arrival_qty = int(sample.get("Arrival Qty", 0) or 0)
            # Stock Qty: count unused units in the group
            statuses    = grp["Status"].astype(str).str.strip().str.lower() if "Status" in grp.columns else pd.Series()
            if not statuses.empty:
                stock_qty = int((statuses == "unused").sum())
            else:
                stock_qty = int(sample.get("Stock Qty", 0) or 0)

            if arrival_qty <= 0:
                continue

            warn_thr = max(1, round(arrival_qty * 0.50))
            crit_thr = max(1, round(arrival_qty * 0.10))

            # Expired flag: only if still has unused stock AND catalogue is expired
            has_expired = False
            cat_exp     = sample.get("Expiration Date")
            if stock_qty > 0 and pd.notna(cat_exp) and cat_exp.date() < today:
                has_expired = True

            std_summary[str(sid)] = {
                "name":        str(sample.get("Reagent Name", "")),
                "mgmt_code":   mgmt,
                "manufacturer":str(sample.get("Manufacturer", "")),
                "catalog":     str(sample.get("Catalog Number", "")),
                "unopened":    stock_qty,
                "has_expired": has_expired,
            }

            if has_expired or stock_qty <= crit_thr:
                critical_list.append(str(sid))
            elif stock_qty <= warn_thr:
                warning_list.append(str(sid))

        result["standards"]["critical"] = critical_list
        result["standards"]["warning"]  = warning_list
        result["standards"]["summary"]  = std_summary

    # ══════════════════════════════════════════════════════════════════════════
    # CELL CULTURE  (unchanged logic — hardcoded MCB/WCB thresholds)
    # ══════════════════════════════════════════════════════════════════════════
    if not cell_df.empty and "Cell Name" in cell_df.columns:
        l929 = cell_df[
            cell_df["Cell Name"].astype(str).str.strip().str.upper() == "L-929"
        ].copy()

        GROUPS = {
            "L_MCB": {"label": "L-929 MCB", "warn_thr": 2,  "count": 0, "manufacturer": "ATCC"},
            "L_WCB": {"label": "L-929 WCB", "warn_thr": 10, "count": 0, "manufacturer": "ATCC"},
        }

        ctrl_col = next((c for c in l929.columns if "control" in c.lower()), None)
        if ctrl_col:
            for _, row in l929.iterrows():
                ctrl   = str(row.get(ctrl_col, "")).strip()
                status = str(row.get("Status", "")).strip().lower()
                # In cell culture: "unavailable" = stocked in LN2 (counted as stock)
                if status != "unavailable":
                    continue
                for prefix, grp in GROUPS.items():
                    if ctrl.startswith(prefix):
                        grp["count"] += 1
                        if not grp["manufacturer"] or grp["manufacturer"] == "ATCC":
                            mfr = str(row.get("Manufacturer", "")).strip()
                            if mfr:
                                grp["manufacturer"] = mfr
                        break

        for prefix, grp in GROUPS.items():
            entry = {
                "Cell Name":   "L-929",
                "Label":       grp["label"],
                "Control No.": prefix,
                "Manufacturer":grp["manufacturer"],
                "Stock":       grp["count"],
                "_mgmt":       prefix,
            }
            if grp["count"] == 0:
                result["cell_culture"]["critical"].append(entry)
            elif grp["count"] <= grp["warn_thr"]:
                result["cell_culture"]["warning"].append(entry)

    return result

# =============================================================================
#  QC1 DASHBOARD & REAGENT PAGES (unchanged, but adapted to use division)
# =============================================================================
def dashboard_page():
    from collections import defaultdict

    division  = st.session_state.division
    sheet_key = st.session_state.sheet_key
    client    = st.session_state.client

    # ── Header ────────────────────────────────────────────────────────────────
