# STANDARDS PAGE  — v4
#
# New in v4:
#   • generate_standard_label_html() — 80×35mm label matching SQC01-018-A01
#   • Auto-generates labels on "Save to Quarantine" (quarantine label)
#   • Auto-generates labels on "Create Inventory Records" (per-aliquot labels)
#   • 🏷 Labels popover with multiselect for printing multiple labels at once
#     (same pattern as cell culture page)
#   • show_std_label_expander() for print / dismiss
# ══════════════════════════════════════════════════════════════════════════════

def _standard_unit_status_counts(df_std, df_use):
    """
    Count standard UNITS by effective status → (unused, used, disposed).

    Mirrors the Standards inventory overview (show_standard_detail_popover's
    _effective_status) so the Dashboard card matches the inventory view exactly:
      • one count per standard unit row in qc1standards (NOT per aliquot)
      • voided units (Is Voided == TRUE) are excluded
      • a 'used' bottle whose aliquots are ALL disposed counts as 'disposed'
        (aliquots live in qc1standardusages, matched by Standard ID + Unit Label)

    The live status values are 'unused' / 'used' / 'disposed' — the old dashboard
    counted 'unopened' / 'opened', which never matched, so it always read 0/0/n.
    """
    unused = used = disposed = 0
    if df_std is None or df_std.empty:
        return unused, used, disposed

    # (Standard ID, Unit Label) → list of that unit's aliquot statuses
    ali_by_key = {}
    if df_use is not None and not df_use.empty and "Is Aliquot" in df_use.columns:
        ali = df_use[df_use["Is Aliquot"].astype(str).str.upper() == "TRUE"]
        for _, a in ali.iterrows():
            key = (str(a.get("Standard ID", "")).strip(),
                   str(a.get("Unit Label", "")).strip())
            ali_by_key.setdefault(key, []).append(
                str(a.get("Aliquot Status", "")).strip().lower()
            )

    for _, unit in df_std.iterrows():
        if str(unit.get("Is Voided", "")).strip().upper() == "TRUE":
            continue
        raw = str(unit.get("Status", "")).strip().lower()
        if raw == "used":
            key = (str(unit.get("Standard ID", "")).strip(),
                   str(unit.get("Aliquot Serial", "")).strip())
            ali_statuses = ali_by_key.get(key, [])
            if ali_statuses and all(s == "disposed" for s in ali_statuses):
                raw = "disposed"
        if raw == "unused":
            unused += 1
        elif raw == "used":
            used += 1
        elif raw == "disposed":
            disposed += 1
    return unused, used, disposed


def _get_active_standard_ids(df_std, df_qua=None, allow_expired=False):
    """
    Return set of Standard IDs that are eligible for selection in dropdowns.
    Excludes: voided, expired, all-disposed, and any whose quarantine record
    is still Quarantine or Rejected (i.e. never approved into inventory).
    Mirrors the reagent page's _get_active_reagent_ids() logic.

    allow_expired defaults to False everywhere in this module, including
    Register Usage, which hard-blocks expired standards unconditionally
    (compliance decision) — independent of ALLOW_EXPIRED_UNIT_OPEN, which
    only gates the Reagents module's own expiry check elsewhere in this file.
    """
    active = set()
    if df_std.empty:
        return active
    today_d = date.today()
    for sid, grp in df_std.groupby("Standard ID"):
        sample = grp.iloc[0]
        # Voided
        if str(sample.get("Is Voided", "")).upper() == "TRUE":
            continue
        # Expired
        exp_raw = sample.get("Expiry Date", "")
        exp_dt = pd.to_datetime(exp_raw, errors="coerce")
        if not allow_expired and pd.notna(exp_dt) and exp_dt.date() < today_d:
            continue
        # All disposed (out of stock)
        statuses = grp["Status"].str.strip().str.lower()
        all_disp = (statuses == "disposed").all() and len(grp) > 0
        if all_disp:
            continue
        active.add(str(sid))
    return active

def _next_aliquot_num(df_use_local, mgmt_code: str) -> int:
        """
        Return the next sequential aliquot number for *mgmt_code*.
 
        Scans existing usage rows whose Aliquot Name ends in "-A{n}" for the
        same management code and returns max(n) + 1.  Returns 1 when no prior
        aliquots exist, so the very first aliquot is always -A1.
        """
        if df_use_local.empty or "Aliquot Name" not in df_use_local.columns:
            return 1
        mask = (
            (df_use_local["Is Aliquot"].astype(str).str.upper() == "TRUE") &
            (df_use_local["Management Code"].astype(str).str.strip()
             == str(mgmt_code).strip())
        )
        ali_rows = df_use_local[mask]
        if ali_rows.empty:
            return 1
        max_n = 0
        for name in ali_rows["Aliquot Name"].dropna():
            m = re.search(r"-A(\d+)$", str(name), re.IGNORECASE)
            if m:
                max_n = max(max_n, int(m.group(1)))
        return max_n + 1
#=============================================================================
#  Standard label — real PDF generation (59.5mm x 33.5mm), reportlab port of
#  the former generate_standard_label_html() design (screenshot-verified
#  faithful port — only the physical page size changed, to match the
#  reagent label's printer/paper-preset). DO NOT change fonts, sizes, column
#  widths, alignment, wrapping behavior, or the drawing logic below.
#  Constants are prefixed STD_ to avoid colliding with the reagent label's
#  module-level PAGE_W/LABEL_FONT/etc (same file, different locked designs).
#  _qr_image_reader() and _wrap_to_fit() are reused as-is from the reagent
#  label module above — identical algorithms, no need for a second copy.
# =============================================================================
STD_PAGE_W = 60 * mm   # match physical label exactly (was 59.5)
STD_PAGE_H = 35 * mm   # match physical label exactly (was 33.5)

STD_LABEL_FONT  = "Helvetica-Bold"
STD_VALUE_FONT  = "Helvetica"
STD_LABEL_SIZE  = 4.5
STD_VALUE_SIZE  = 5
STD_FOOTER_SIZE = 3.8
STD_PAD_LEFT    = 0.6 * mm


def _draw_standard_label(c, stock_name, std_no, expiry_date, assay, storage_condition, qr_data):
    qr_col_w = 10 * mm
    label1_w = 11 * mm
    value1_w = 12 * mm
    label2_w = 9 * mm

    x1 = qr_col_w
    x2 = x1 + label1_w
    x3 = x2 + value1_w
    x4 = x3 + label2_w
    x5 = STD_PAGE_W
    value2_w = x5 - x4

    footer_h = 3 * mm
    content_top = STD_PAGE_H - INSET
    content_bottom = footer_h
    content_h = content_top - content_bottom
    n_rows = 3
    row_h = content_h / n_rows
    row_tops = [content_top - i * row_h for i in range(n_rows + 1)]

    # ── Table border — only around the QR+rows area, NOT the whole page.
    # The footer sits below this, unbordered, same as the original HTML
    # design (its wrapping <div> and footer <div> never had a border either).
    c.setLineWidth(0.6)
    c.rect(INSET, content_bottom, STD_PAGE_W - 2 * INSET, content_h, stroke=1, fill=0)

    # ── Footer (no border — floats below the table box, same position) ─────
    c.setFont(STD_VALUE_FONT, STD_FOOTER_SIZE)
    c.drawString(1 * mm, 1 * mm, "Form info : SQC01-018-A01 (Ver. 2.0)")
    c.setFont("Helvetica-BoldOblique", STD_FOOTER_SIZE)
    c.drawRightString(STD_PAGE_W - 1 * mm, 1 * mm, "CONFIDENTIAL")

    # ── Internal grid lines (within the table box only) ────────────────────
    c.line(x1, content_bottom, x1, content_top)       # QR | rest
    c.line(x2, content_bottom, x2, content_top)       # label1 | value1 (row0's value spans past this)
    c.line(x3, row_tops[3], x3, row_tops[1])          # value1 | label2 (rows 1-2 only)
    c.line(x4, row_tops[3], x4, row_tops[1])          # label2 | value2 (rows 1-2 only)
    c.line(x1, row_tops[1], STD_PAGE_W - INSET, row_tops[1])  # row0/row1 divider
    c.line(x1, row_tops[2], STD_PAGE_W - INSET, row_tops[2])  # row1/row2 divider

    def _mid(row_idx):
        top, bottom = row_tops[row_idx], row_tops[row_idx + 1]
        return (top + bottom) / 2

    def _label(x, row_idx, text, two_line=False):
        c.setFont(STD_LABEL_FONT, STD_LABEL_SIZE)
        mid = _mid(row_idx)
        if not two_line:
            c.drawString(x + STD_PAD_LEFT, mid - STD_LABEL_SIZE * 0.35, text)
        else:
            line1, line2 = text
            c.drawString(x + STD_PAD_LEFT, mid + STD_LABEL_SIZE * 0.25, line1)
            c.drawString(x + STD_PAD_LEFT, mid - STD_LABEL_SIZE * 0.85, line2)

    def _value_single(x, row_idx, text):
        c.setFont(STD_VALUE_FONT, STD_VALUE_SIZE)
        mid = _mid(row_idx)
        c.drawString(x + STD_PAD_LEFT, mid - STD_VALUE_SIZE * 0.35, text)

    def _value_wrapped(x, row_idx, text, max_w_mm):
        lines, size = _wrap_to_fit(text, STD_VALUE_FONT, STD_VALUE_SIZE, max_w_mm)
        c.setFont(STD_VALUE_FONT, size)
        mid = _mid(row_idx)
        if len(lines) == 1:
            c.drawString(x + STD_PAD_LEFT, mid - size * 0.35, lines[0])
        else:
            c.drawString(x + STD_PAD_LEFT, mid + size * 0.25, lines[0])
            c.drawString(x + STD_PAD_LEFT, mid - size * 0.85, lines[1])

    # ── QR code ─────────────────────────────────────────────────────────────
    qr_img = _qr_image_reader(qr_data)
    qr_size = min(qr_col_w - 1.5 * mm, content_h - 2 * mm)
    qr_x = (qr_col_w - qr_size) / 2
    qr_y = content_bottom + (content_h - qr_size) / 2
    c.drawImage(qr_img, qr_x, qr_y, width=qr_size, height=qr_size,
                preserveAspectRatio=True, mask="auto")

    # ── Row 0 — Stock name (wide value, spans to right edge of the label) ───
    _label(x1, 0, "Stock name")
    stock_name_max_w = (STD_PAGE_W - INSET - x2 - STD_PAD_LEFT - 0.5 * mm) / mm
    _value_wrapped(x2, 0, stock_name, stock_name_max_w)

    # ── Row 1 — Expiry date | Assay ─────────────────────────────────────────
    _label(x1, 1, "Expiry date")
    _value_wrapped(x2, 1, expiry_date, (value1_w - STD_PAD_LEFT - 0.3 * mm) / mm)
    _label(x3, 1, "Assay")
    _value_wrapped(x4, 1, assay, (value2_w - STD_PAD_LEFT - 0.5 * mm) / mm)

    # ── Row 2 — STD No. | Storage condition ─────────────────────────────────
    _label(x1, 2, "STD No.")
    _value_wrapped(x2, 2, std_no, (value1_w - STD_PAD_LEFT - 0.3 * mm) / mm)
    _label(x3, 2, ("Storage", "condition"), two_line=True)
    _value_wrapped(x4, 2, storage_condition, (value2_w - STD_PAD_LEFT - 0.5 * mm) / mm)


def generate_standard_label_pdf(output_path, stock_name, std_no, expiry_date,
                                 assay, storage_condition, qr_data):
    """Single-label PDF to a path (kept for backward compatibility / reprints)."""
    c = canvas.Canvas(output_path, pagesize=(STD_PAGE_W, STD_PAGE_H))
    _draw_standard_label(c, stock_name, std_no, expiry_date, assay, storage_condition, qr_data)
    c.showPage()
    c.save()


def generate_standard_labels_batch_pdf_bytes(labels: list) -> bytes:
    """
    Renders multiple standard labels into a single multi-page PDF (one page
    per label, each page sized STD_PAGE_W x STD_PAGE_H) and returns raw PDF
    bytes — for Streamlit's download_button, no temp files needed.

    `labels` is a list of dicts, each using the same keyword arguments as
    generate_standard_label_pdf() (stock_name, std_no, expiry_date, assay,
    storage_condition, qr_data).
    """
    if not labels:
        raise ValueError("labels list is empty — nothing to render")
    buf = io.BytesIO()
    c = canvas.Canvas(buf, pagesize=(STD_PAGE_W, STD_PAGE_H))
    for lbl in labels:
        _draw_standard_label(c, **lbl)
        c.showPage()
    c.save()
    buf.seek(0)
    return buf.getvalue()

