                st.markdown(
                    '<span style="display:inline-block;padding:3px 10px;border-radius:8px;'
                    'background:#F0FFF4;color:#276749;border:1.5px solid #9AE6B4;'
                    'font-size:12px;font-weight:700;">✓ Purchased</span>',
                    unsafe_allow_html=True,
                )
