from contextlib import contextmanager

@contextmanager
def qc2_processing(message: str = "Processing request..."):
    """
    Reusable loading-indicator wrapper for QC2 submit/save/release actions.
    Wrap the actual processing step (the part that writes to the database
    or does other noticeable work) in `with qc2_processing("..."):` — shows
    a native Streamlit spinner with `message` for the duration of the
    block, and clears automatically whether the block finishes normally or
    raises. No artificial delay is added; QC1 is untouched since this is
    only used by QC2 pages below this point in the file.
    """
    with st.spinner(message):
        yield

def clear_scan_input(key: str):
    """Clear a scan input field by resetting its session state key."""
    if key in st.session_state:
        del st.session_state[key]

