def qc2_stock_opname_page():
    _ensure_qc2_session_aliases()
    st.title("Stock Opname")
    st.caption("Count your actual physical stock and compare it with the system record.")

    # ── Load all data ───────────────────────────────────────────
    df_media    = load_data_cached("QC2_Media")
    df_reagent  = load_data_cached("QC2_Reagent")
    df_bi_in    = load_data_cached("QC2_BI_Inbound")
    df_bi_out   = load_data_cached("QC2_BI_Usage")
    df_cult_in  = load_data_cached("QC2_Culture_Inbound")
    df_cult_out = load_data_cached("QC2_Culture_Usage")

    try:
        df_so_history = load_data_cached("QC2_Master_SO")
        if df_so_history is None or df_so_history.empty:
            df_so_history = pd.DataFrame()
        else:
            df_so_history = df_so_history.dropna(how='all')
    except:
        df_so_history = pd.DataFrame()

    # Legacy/unused columns from the old Sheets-era schema — always empty,
    # never populated by this page. Drop them so they don't clutter History.
    df_so_history = df_so_history.drop(
        columns=[c for c in ["COA_MSDS", "GHS_Category"] if c in df_so_history.columns]
    )

    # Exclude voided records from every category — mirrors QC1's exclusion of
    # voided reagents/units before counting system stock.
    def _exclude_voided(df):
        if df.empty:
            return df
        if 'Status' in df.columns:
            df = df[~df['Status'].astype(str).str.strip().str.lower().str.contains('void', na=False)]
        if 'Is Voided' in df.columns:
            df = df[df['Is Voided'].astype(str).str.upper() != 'TRUE']
        return df

    df_media   = _exclude_voided(df_media)
    df_reagent = _exclude_voided(df_reagent)
    df_bi_in   = _exclude_voided(df_bi_in)
    df_cult_in = _exclude_voided(df_cult_in)

    # ── Build item list ─────────────────────────────────────────
    items = []

    if not df_media.empty:
        for _, r in df_media.iterrows():
            items.append({
                "Category": "Media",
                "Code": str(r.get("Management_Code", "-")),
                "Item": str(r.get("Nama", "-")),
                "System_Stock": safe_int(r.get("Total_Pcs_Stock", 0)),
                "Unit": "pcs"
            })

    if not df_reagent.empty:
        for _, r in df_reagent.iterrows():
            items.append({
                "Category": "Reagent",
                "Code": str(r.get("Management_Code", "-")),
                "Item": str(r.get("Reagent_Name", "-")),
                "System_Stock": safe_int(r.get("Quantity", 0)),
                "Unit": "pcs"
            })

    if not df_bi_in.empty:
        for _, r in df_bi_in.iterrows():
            mgmt = str(r.get("Management Code", "-"))
            qty_in  = safe_int(r.get("Qty In (Pcs)", 0))
            qty_out = 0
            if not df_bi_out.empty and "Management Code" in df_bi_out.columns:
                qty_out = df_bi_out[df_bi_out["Management Code"].astype(str) == mgmt]["Qty Out (Pcs)"].apply(safe_int).sum()
            items.append({
                "Category": "BI",
                "Code": mgmt,
                "Item": str(r.get("Item Name", "-")),
                "System_Stock": max(0, qty_in - qty_out),
                "Unit": "pcs"
            })

    if not df_cult_in.empty:
        for _, r in df_cult_in.iterrows():
            mgmt = str(r.get("Management Code", "-"))
            qty_in  = safe_int(r.get("Qty In (Pcs)", 0))
            qty_out = 0
            if not df_cult_out.empty and "Management Code" in df_cult_out.columns:
                qty_out = df_cult_out[df_cult_out["Management Code"].astype(str) == mgmt]["Qty Out (Pcs)"].apply(safe_int).sum()
            items.append({
                "Category": "Standard Strain",
                "Code": mgmt,
                "Item": str(r.get("Item Name", "-")),
                "System_Stock": max(0, qty_in - qty_out),
                "Unit": "pcs"
            })

    # ── Tabs ────────────────────────────────────────────────────
    tab_input, tab_history, tab_pending = st.tabs(["New SO", "SO History", "Pending Resolution"])

    # ═══════════════════════════════════════════════════════════
    with tab_input:
        if not has_permission("can_input"):
            st.info("🔒 Stock Opname entry restricted to Analis and QA.")
        elif not items:
            st.info("No inventory data found. Please input items first.")
        else:
            so_date = datetime.now().strftime('%d %b %Y').upper()
            pic     = st.session_state.user_name

            st.markdown(f"**Date:** {so_date} &nbsp;&nbsp; **PIC:** {pic}")
            st.write("")

            # Category filter
            cat_options = ["All", "Media", "Reagent", "BI", "Standard Strain"]
            cat_filter  = st.selectbox("Filter by Category", cat_options, key="so_cat")
            filtered    = [x for x in items if cat_filter == "All" or x["Category"] == cat_filter]

            st.write("---")

            so_results = []

            for i, row in enumerate(filtered):
                sys_stock = row["System_Stock"]

                c1, c2, c3, c4 = st.columns([3, 1, 1, 3])

                c1.markdown(
                    f"<span style='font-size:18px; font-weight:600;'>{row['Item']}</span>  \n"
                    f"<span style='font-size:14px;color:var(--color-text-secondary);'>"
                    f"{row['Category']} · {row['Code']}</span>",
                    unsafe_allow_html=True
                )
                c2.metric("System", f"{sys_stock} pcs")

                actual = c3.number_input(
                    "Actual",
                    min_value=0, step=1,
                    value=int(sys_stock),
                    key=f"actual_{i}",
                    label_visibility="visible"
                )

                diff = actual - sys_stock

                if diff == 0:
                    notes = "Balance"
                    c4.success("✅ Balance")
                else:
                    label = f"⬆️ +{diff} surplus" if diff > 0 else f"⬇️ {diff} shortage"
                    if diff > 0:
                        c4.warning(label)
                    else:
                        c4.error(label)
                    notes = st.text_input(
                        f"Notes for {row['Item']}",
                        placeholder="e.g. 2 pcs broken, 1 pcs missing label",
                        key=f"notes_{i}"
                    )

                so_results.append({
                    "Date": so_date,
                    "Category": row["Category"],
                    "Management_Code": row["Code"],
                    "Item_Name": row["Item"],
                    "System_Stock": sys_stock,
                    "Actual_Stock": actual,
                    "Difference": diff,
                    "Status": "Balance" if diff == 0 else ("Surplus" if diff > 0 else "Shortage"),
                    "Notes": notes,
                    "PIC": pic,
                    "Timestamp": datetime.now().strftime('%d/%m/%Y %H:%M:%S')
                })

                st.divider()

            # ── Summary metrics ──────────────────────────────────
            total    = len(so_results)
            balanced = sum(1 for r in so_results if r["Status"] == "Balance")
            surplus  = sum(1 for r in so_results if r["Status"] == "Surplus")
            shortage = sum(1 for r in so_results if r["Status"] == "Shortage")

            m1, m2, m3, m4 = st.columns(4)
            m1.metric("Total Items", total)
            m2.metric("✅ Balance",  balanced)
            m3.metric("⬆️ Surplus",  surplus)
            m4.metric("⬇️ Shortage", shortage)

            st.write("")

            col_save, col_print = st.columns(2)

            # ── Save ─────────────────────────────────────────────
            with col_save:
                if st.button("💾 Save SO", type="primary", width='stretch'):
                    so_id = db.next_qc2_so_id()

                    try:
                        with qc2_processing("Saving data..."):
                            # Direct INSERT — never a full-table rewrite, so
                            # so_id/resolution_status on every earlier batch
                            # survives every subsequent New SO save.
                            db.insert_qc2_stock_opname_rows(so_id, [{
                                "timestamp":       r["Timestamp"],
                                "so_date":         r["Date"],
                                "pic":             r["PIC"],
                                "category":        r["Category"],
                                "management_code": r["Management_Code"],
                                "item_name":       r["Item_Name"],
                                "system_stock":     r["System_Stock"],
                                "actual_stock":    r["Actual_Stock"],
                                "difference":      r["Difference"],
                                "status":          r["Status"],
                                "remark":          r["Notes"],
                            } for r in so_results])
                            try:
                                db.open_qc2_stockopname_discrepancies(so_id)
                            except Exception:
                                pass
                        log_audit("STOCK OPNAME", "SO",
                            f"SO {so_id} saved: {total} items | Balance: {balanced} | Surplus: {surplus} | Shortage: {shortage}")
                        # Reset the per-item widgets so the form comes back
                        # fresh instead of showing the just-saved values.
                        for i in range(len(filtered)):
                            st.session_state.pop(f"actual_{i}", None)
                            st.session_state.pop(f"notes_{i}", None)
                        st.success(f"✅ Stock Opname saved! {total} items recorded ({so_id}).")
                        st.rerun()
                    except Exception as e:
                        st.error(f"Failed to save: {e}")


    # ═══════════════════════════════════════════════════════════
    with tab_history:
        st.subheader("SO History")
        if df_so_history.empty:
            st.info("No SO records yet. Complete a Stock Opname first.")
        else:
            # Date-range filter, mirrors QC1's From/To pair.
            if "Date" in df_so_history.columns:
                _dates = pd.to_datetime(df_so_history["Date"], errors="coerce", dayfirst=True)
                _valid_dates = _dates.dropna()
                if not _valid_dates.empty:
                    _min_date, _max_date = _valid_dates.min().date(), _valid_dates.max().date()
                    col_f1, col_f2 = st.columns(2)
                    with col_f1:
                        date_from = st.date_input("From", value=_min_date, min_value=_min_date,
                                                   max_value=_max_date, key="so_hist_date_from")
                    with col_f2:
                        date_to = st.date_input("To", value=_max_date, min_value=_min_date,
                                                 max_value=_max_date, key="so_hist_date_to")
                    _mask = (_dates.dt.date >= date_from) & (_dates.dt.date <= date_to)
                    df_view = df_so_history[_mask]
                    # Print Report below expects either "All Dates" or one
                    # exact, parseable date string — keep it backward
                    # compatible rather than touching that block itself.
                    selected_date = str(date_from) if date_from == date_to else "All"
                else:
                    df_view = df_so_history
                    selected_date = "All"
            else:
                df_view = df_so_history
                selected_date = "All"

            # QC2_Master_SO carries two column generations: the legacy
            # Sheets-era names (space-separated, from QC2_COLUMN_STANDARDS)
            # and the current Supabase names (underscore, written by the
            # "New SO" tab above). load_data() unions both, so df_view has
            # every field twice. Collapse each pair into one display column
            # instead of rendering both — underlying storage is untouched.
            def _so_col(df, name):
                """Pass a single, non-duplicated column through unchanged (native dtype kept)."""
                return df[name] if name in df.columns else pd.Series("-", index=df.index)

            def _so_col_coalesced(df, primary, legacy):
                """Prefer the populated generation of a duplicated field, string-typed
                since the two generations may not share a dtype (e.g. int vs '-')."""
                prim = df[primary].astype(str) if primary in df.columns else pd.Series("-", index=df.index)
                leg  = df[legacy].astype(str) if legacy in df.columns else pd.Series("-", index=df.index)
                blank = prim.isin(["", "-", "nan", "None"])
                return prim.where(~blank, leg)

            df_display = pd.DataFrame({
                "SO ID":           _so_col(df_view, "so_id").fillna("-"),
                "Date":            _so_col(df_view, "Date"),
                "Timestamp":       _so_col(df_view, "Timestamp"),
                "PIC":             _so_col(df_view, "PIC"),
                "Category":        _so_col(df_view, "Category"),
                "Management Code": _so_col_coalesced(df_view, "Management_Code", "Management Code"),
                "Item Name":       _so_col_coalesced(df_view, "Item_Name", "Item Name"),
                "System Stock":    _so_col_coalesced(df_view, "System_Stock", "System Stock"),
                "Actual Stock":    _so_col_coalesced(df_view, "Actual_Stock", "Actual Stock"),
                "Difference":      _so_col(df_view, "Difference"),
                "Status":          _so_col(df_view, "Status"),
                "Notes":           _so_col_coalesced(df_view, "Notes", "Remark"),
            })

            # Resolution status — reuses Phase A's resolution map instead of
            # a separate query. Legacy rows (no so_id) show "—", matching
            # QC1's handling of pre-existing fields that predate a column.
            try:
                _resolution_map = db.load_qc2_stockopname_resolution_map()
            except Exception:
                _resolution_map = {}

            def _discrepancy_status_text(row):
                if str(row["Status"]) == "Balance":
                    return "—"
                info = _resolution_map.get((str(row["SO ID"]), str(row["Category"]), str(row["Management Code"])))
                if not info:
                    return "⚠️ Unresolved"
                if info.get("status") == "resolved":
                    via = str(info.get("resolved_via") or "").replace("_", " ")
                    try:
                        date_str = pd.to_datetime(info.get("resolved_at")).strftime("%Y-%m-%d")
                        return f"✅ Resolved via {via} ({date_str})"
                    except Exception:
                        return f"✅ Resolved via {via}"
                return "⚠️ Unresolved"

            df_display["Discrepancy Status"] = df_display.apply(_discrepancy_status_text, axis=1)

            def _color_status(val):
                if val == "Balance":   return "background-color:#F0FDF4;color:#16A34A;font-weight:600;"
                elif val == "Surplus": return "background-color:#EFF6FF;color:#2563EB;font-weight:600;"
                elif val == "Shortage": return "background-color:#FEF2F2;color:#DC2626;font-weight:600;"
                return ""

            def _color_diff(val):
                try:
                    v = safe_int(val, 0)
                    if v > 0:   return "color:#2563EB;font-weight:600;"
                    elif v < 0: return "color:#DC2626;font-weight:600;"
                    return "color:#16A34A;font-weight:600;"
                except Exception:
                    return ""

            def _color_discrepancy_status(val):
                val = str(val)
                if "Unresolved" in val: return "color:#DC2626;font-weight:600;"
                elif "Resolved" in val: return "color:#16A34A;font-weight:600;"
                return ""

            # Grouped by SO session, most recent first — same layout and
            # navigation as QC1's SO History (one expander per Stock Opname
            # session instead of one flat table).
            def _so_sort_key(sid):
                m = re.search(r"(\d+)$", str(sid))
                return int(m.group(1)) if m else 0

            so_ids = sorted(df_display["SO ID"].dropna().unique().tolist(),
                             key=_so_sort_key, reverse=True)

            for so_id in so_ids:
                so_group = df_display[df_display["SO ID"] == so_id]
                if so_group.empty:
                    continue

                so_date_str = str(so_group["Date"].iloc[0])
                so_pic      = str(so_group["PIC"].iloc[0])
                so_ts       = str(so_group["Timestamp"].iloc[0])
                n_balance   = len(so_group[so_group["Status"] == "Balance"])
                n_surplus   = len(so_group[so_group["Status"] == "Surplus"])
                n_shortage  = len(so_group[so_group["Status"] == "Shortage"])

                label_suffix = (f"  🔴 {n_shortage} Shortage" if n_shortage > 0
                                else f"  🔵 {n_surplus} Surplus" if n_surplus > 0
                                else "  ✅ All Balance")

                with st.expander(
                    f"**{so_id}** — {so_date_str} | PIC: {so_pic} | {len(so_group)} items {label_suffix}",
                    expanded=False
                ):
                    m1, m2, m3, m4 = st.columns(4)
                    m1.metric("Total Items", len(so_group))
                    m2.metric("✅ Balance",  n_balance)
                    m3.metric("🔵 Surplus",  n_surplus)
                    m4.metric("🔴 Shortage", n_shortage)
                    st.caption(f"Conducted: {so_date_str}  |  Saved: {so_ts}")
                    st.divider()

                    display_table = so_group[[
                        "Category", "Management Code", "Item Name",
                        "System Stock", "Actual Stock", "Difference",
                        "Status", "Notes", "Discrepancy Status",
                    ]].copy().reset_index(drop=True)
                    display_table.index += 1

                    styled = (display_table.style
                              .map(_color_status, subset=["Status"])
                              .map(_color_diff, subset=["Difference"])
                              .map(_color_discrepancy_status, subset=["Discrepancy Status"]))
                    st.dataframe(styled, use_container_width=True)

            # ── Print Report ─────────────────────────────────────
            st.write("---")
            st.caption("🖨️ Print the SO report for the selected date above.")

            if st.button("🖨️ Print SO Report", width='stretch'):
              with qc2_processing("Generating report..."):
                if df_view.empty:
                    st.warning("No data to print.")
                else:
                    logo_src    = get_logo_base64()
                    pic_hist    = df_view["PIC"].iloc[0] if "PIC" in df_view.columns else "-"
                    date_hist   = selected_date if selected_date != "All" else "All Dates"

                    total_h    = len(df_view)
                    balanced_h = len(df_view[df_view["Status"] == "Balance"]) if "Status" in df_view.columns else 0
                    surplus_h  = len(df_view[df_view["Status"] == "Surplus"])  if "Status" in df_view.columns else 0
                    shortage_h = len(df_view[df_view["Status"] == "Shortage"]) if "Status" in df_view.columns else 0

                    rows_html = ""
                    for _, r in df_view.iterrows():
                        diff_val   = safe_int(r.get("Difference", 0))
                        diff_color = "#27AE60" if diff_val == 0 else ("#E67E22" if diff_val > 0 else "#E74C3C")
                        diff_str   = f"+{diff_val}" if diff_val > 0 else str(diff_val)
                        status     = str(r.get("Status", "-"))
                        rows_html += f"""
                        <tr>
                            <td>{r.get('Category', '-')}</td>
                            <td>{r.get('Management_Code', '-')}</td>
                            <td>{r.get('Item_Name', '-')}</td>
                            <td style="text-align:center;">{safe_int(r.get('System_Stock', 0))}</td>
                            <td style="text-align:center;">{safe_int(r.get('Actual_Stock', 0))}</td>
                            <td style="text-align:center;color:{diff_color};font-weight:bold;">{diff_str}</td>
                            <td style="text-align:center;color:{diff_color};font-weight:bold;">{status}</td>
                            <td>{r.get('Notes', '-')}</td>
                        </tr>"""

                    report_html = f"""
                    <html><head><style>
                        @page {{ size: A4 landscape; margin: 12mm; }}
                        body {{ font-family: Arial, sans-serif; font-size: 10px; margin: 0; }}
                        .header-table {{ width:100%; border-collapse:collapse; margin-bottom:10px; }}
                        .logo-cell  {{ width:15%; border:1px solid #000; padding:6px; text-align:center; vertical-align:middle; }}
                        .title-cell {{ width:70%; border:1px solid #000; padding:6px; text-align:center; vertical-align:middle; }}
                        .info-cell  {{ width:15%; border:1px solid #000; padding:6px; font-size:8px; vertical-align:top; }}
                        .main-table {{ width:100%; border-collapse:collapse; margin-bottom:10px; }}
                        .main-table th {{ background:#2c3e50; color:#fff; padding:5px; text-align:left; font-size:9px; }}
                        .main-table td {{ padding:4px 5px; border-bottom:1px solid #ddd; font-size:9px; }}
                        .main-table tr:nth-child(even) {{ background:#f9f9f9; }}
                        .summary {{ display:flex; gap:16px; margin-bottom:10px; }}
                        .summary-box {{ border:1px solid #ccc; border-radius:4px; padding:5px 12px; text-align:center; font-size:9px; }}
                        .sign-table {{ width:100%; border-collapse:collapse; margin-top:14px; }}
                        .sign-table td {{ border:1px solid #000; padding:8px; font-size:9px; width:33%; }}
                    </style></head><body>
                    <table class="header-table"><tr>
                        <td class="logo-cell">
                            {f'<img src="{logo_src}" style="max-height:60px;max-width:100%;">' if logo_src else ''}
                            <div style="font-size:9px;margin-top:4px;">PT SELATOX BIO PHARMA</div>
                        </td>
                        <td class="title-cell">
                            <b style="font-size:13px;">Stock Opname Report</b><br>
                            <i style="font-size:9px;">QC Microbiology Laboratory</i><br>
                            <div style="margin-top:5px;display:inline-block;
                                        background:#2c3e50;color:#fff;
                                        border-radius:4px;padding:2px 14px;
                                        font-size:10px;font-weight:bold;letter-spacing:1px;">
                                SO Period: {pd.to_datetime(date_hist, dayfirst=True, errors='coerce').strftime('%B %Y').upper() if date_hist != 'All Dates' else 'ALL PERIODS'}
                            </div>
                        </td>
                        <td class="info-cell">
                            <b>SO Period:</b> {pd.to_datetime(date_hist, dayfirst=True, errors='coerce').strftime('%B %Y').upper() if date_hist != 'All Dates' else 'All Periods'}<br>
                            Date: {date_hist}<br>
                            PIC: {pic_hist}<br>
                            Printed: {datetime.now().strftime('%d %b %Y %H:%M').upper()}
                        </td>
                    </tr></table>
                    <div class="summary">
                        <div class="summary-box"><b>{total_h}</b><br>Total Items</div>
                        <div class="summary-box" style="color:#27AE60;"><b>{balanced_h}</b><br>Balance</div>
                        <div class="summary-box" style="color:#E67E22;"><b>{surplus_h}</b><br>Surplus</div>
                        <div class="summary-box" style="color:#E74C3C;"><b>{shortage_h}</b><br>Shortage</div>
                    </div>
                    <table class="main-table">
                        <tr>
                            <th>Category</th><th>Code</th><th>Item Name</th>
                            <th>System Stock</th><th>Actual Stock</th>
                            <th>Difference</th><th>Status</th><th>Notes</th>
                        </tr>
                        {rows_html}
                    </table>
                    <table class="sign-table"><tr>
                        <td>Prepared by:<br><br><br>___________________<br>{pic_hist}</td>
                        <td>Checked by (Supervisor):<br><br><br>___________________<br>Date: _______________</td>
                        <td>Approved by (QA):<br><br><br>___________________<br>Date: _______________</td>
                    </tr></table>
                    </body></html>
                    """

                    st.components.v1.html(f"""
                    <iframe id="so_hist_print" style="width:0;height:0;border:0;"
                        srcdoc="{report_html.replace(chr(34), '&quot;')}"></iframe>
                    <script>
                        document.getElementById('so_hist_print').onload = function() {{
                            document.getElementById('so_hist_print').contentWindow.print();
                        }}
                    </script>
                    """, height=0)
                    st.success("✅ Report ready for printing.")

    # ═══════════════════════════════════════════════════════════
    with tab_pending:
        st.subheader("Pending Resolution")
        st.caption("Every open discrepancy across all Stock Opname sessions, oldest first.")

        # ── Dialog dispatch — must run before the worklist renders ─────────
        resolve_target = st.session_state.get("qc2_so_resolve_target")
        if resolve_target:
            qc2_resolve_picker_dialog(
                resolve_target["so_id"], resolve_target["category"],
                resolve_target["management_code"], resolve_target["item_name"],
                resolve_target["diff"],
            )

        resolve_action = st.session_state.get("qc2_so_resolve_action")
        if resolve_action:
            kind    = resolve_action["kind"]
            so_id_r = resolve_action["so_id"]
            cat_r   = resolve_action["category"]
            mgmt_r  = resolve_action["management_code"]
            name_r  = resolve_action["item_name"]
            diff_r  = resolve_action["diff"]
            st.session_state.pop("qc2_so_resolve_action", None)

            if cat_r == "Reagent":
                # Reuse the same shared dialogs QC1 uses — they're already
                # division-generic. QC2's Stock Opname doesn't track a
                # specific lot/Reagent ID per row (unlike QC1), so the user
                # picks the lot themselves inside the dialog.
                if kind == "usage":
                    open_dialog("QC2", so_id=so_id_r, resolve_management_code=mgmt_r)
                elif kind == "disposal":
                    discard_dialog("QC2", so_id=so_id_r, resolve_management_code=mgmt_r)
                elif kind == "registration":
                    registration_dialog("QC2", prefill_management_code=mgmt_r,
                                         prefill_qty=max(1, abs(diff_r)),
                                         so_id=so_id_r, resolve_management_code=mgmt_r)
                elif kind == "loss_adjustment":
                    loss_damage_dialog("QC2", so_id=so_id_r, resolve_management_code=mgmt_r)
            elif cat_r == "Media":
                qc2_so_resolve_media_dialog(kind, so_id_r, mgmt_r, name_r, diff_r)
            elif cat_r == "BI":
                qc2_so_resolve_bi_dialog(kind, so_id_r, mgmt_r, name_r, diff_r)
            elif cat_r == "Standard Strain":
                qc2_so_resolve_culture_dialog(kind, so_id_r, mgmt_r, name_r, diff_r)

        # ── Worklist ─────────────────────────────────────────────────────
        try:
            open_df = db.load_open_qc2_stockopname_discrepancies()
        except Exception as e:
            st.error(f"Failed to load pending discrepancies: {e}")
            open_df = pd.DataFrame()

        if open_df.empty:
            st.success("✅ No open discrepancies. All Stock Opname counts are reconciled.")
        else:
            open_df["SO Date"]   = pd.to_datetime(open_df["SO Date"], errors="coerce", dayfirst=True)
            open_df["Timestamp"] = pd.to_datetime(open_df["Timestamp"], errors="coerce", dayfirst=True)
            now_ts = pd.Timestamp.now()
            open_df["Days Open"] = (now_ts - open_df["Timestamp"]).dt.days.clip(lower=0)
            open_df = open_df.sort_values("Days Open", ascending=False).reset_index(drop=True)

            st.metric("Open Discrepancies", len(open_df))
            st.markdown("---")

            hdr = st.columns([2.2, 1.2, 1, 1.5, 1, 1.3])
            for c, label in zip(hdr, ["Item", "Category", "Diff", "From SO", "Days Open", ""]):
                c.markdown(f"**{label}**")
            st.divider()

            for _, r in open_df.iterrows():
                c1, c2, c3, c4, c5, c6 = st.columns([2.2, 1.2, 1, 1.5, 1, 1.3])
                c1.write(f"{r['Item Name']}  \n`{r['Management Code']}`")
                c2.write(str(r["Category"]))
                diff_val  = safe_int(r["Diff"], 0)
                diff_text = f"+{diff_val}" if diff_val > 0 else str(diff_val)
                c3.write(diff_text)
                so_date_disp = r["SO Date"].strftime("%Y-%m-%d") if pd.notna(r["SO Date"]) else "-"
                c4.write(f"{r['SO ID']}  \n{so_date_disp}")
                c5.write(str(int(r["Days Open"])) if pd.notna(r["Days Open"]) else "-")
                if c6.button("Resolve", key=f"qc2_so_resolve_btn_{r['SO ID']}_{r['Category']}_{r['Management Code']}"):
                    st.session_state["qc2_so_resolve_target"] = {
                        "so_id": r["SO ID"],
                        "category": r["Category"],
                        "management_code": r["Management Code"],
                        "item_name": r["Item Name"],
                        "diff": diff_val,
                    }
                    st.rerun()
                st.divider()


def _ensure_qc2_session_aliases():
    st.session_state.user_id = st.session_state.get("user_id", st.session_state.get("username", ""))
    st.session_state.user_role = st.session_state.get("user_role", st.session_state.get("role", "guest"))
    st.session_state.user_name = st.session_state.get("user_name", st.session_state.get("full_name", st.session_state.get("username", "")))


def render_sidebar_navigation():
    render_qc2_global_css()
    _ensure_qc2_session_aliases()
    division = st.session_state.get("division", "QC1")

    # Recomputed fresh at the top of every single script rerun (this
    # function always runs first, before any page/gate check) so delegated
    # access can never go stale and always self-reverts once end_date
    # passes — no cron/manual step needed. Applies to both divisions.
    if division in ("QC1", "QC2"):
        st.session_state["_active_deleg_as_delegate"] = get_active_delegation_as_delegate()
    else:
        st.session_state.pop("_active_deleg_as_delegate", None)

    if "menu" not in st.session_state or not st.session_state.menu:
        st.session_state.menu = "🏠 Dashboard" if division == "QC2" else "Dashboard"
    qc1_menus = {"Dashboard", "Reagent", "Standards", "Cell Culture", "Planning", "Storage Map", "Documentation", "Stock Opname", "User Management"}
    #
    qc2_menus = {"🏠 Dashboard", "Media", "Reagent", "Culture Stock", "BI", "Audit_Trail", "Stock_Opname", "User_Management", "⚙️ Settings"}
    if division == "QC1" and st.session_state.menu not in qc1_menus:
        st.session_state.menu = "Dashboard"
    if division == "QC2" and st.session_state.menu not in qc2_menus:
        st.session_state.menu = "🏠 Dashboard"

    def nav_btn(label, menu_key):
        active = st.session_state.get("menu") == menu_key
        if active:
            st.markdown(f'<div class="sb-active">  {label}</div>', unsafe_allow_html=True)
        elif st.button(f"  {label}", key=f"nav_{division}_{menu_key}", use_container_width=True):
            st.session_state.menu = menu_key
            st.rerun()

    with st.sidebar:
        try:
            st.image("logo.png", width=180)
        except Exception:
            st.markdown("<div style='padding:14px 14px 4px 14px;font-size:16px;font-weight:700;color:#1A1953;'>Selatox LIMS</div>", unsafe_allow_html=True)
        st.markdown("<div style='padding:2px 14px 10px 14px;font-size:10px;color:#6B7280;letter-spacing:0.5px;'>Laboratory Information System</div>", unsafe_allow_html=True)
        st.markdown("<hr style='border:none;border-top:1px solid #F0F0F0;margin:0 0 6px 0;'>", unsafe_allow_html=True)
        display_name = st.session_state.get("full_name") or st.session_state.get("user_name") or st.session_state.get("username") or "User"
        initials = "".join([w[0].upper() for w in str(display_name).split()[:2]]) or "?"
        role_display = str(st.session_state.get("role") or st.session_state.get("user_role") or "user").capitalize()
        st.markdown(f"""
        <div class="sb-user-row">
            <div class="sb-avatar">{initials}</div>
            <div>
                <div class="sb-user-name">{display_name}</div>
                <div class="sb-user-role">{role_display} ? {division}</div>
            </div>
        </div>
        """, unsafe_allow_html=True)

        if division == "QC2":
            st.markdown('<span class="sb-section">Main</span>', unsafe_allow_html=True)
            nav_btn("Dashboard", "🏠 Dashboard")
            st.markdown('<span class="sb-section">Inventory</span>', unsafe_allow_html=True)
            nav_btn("Media Management", "Media")
            nav_btn("Reagent Tracking", "Reagent")
            nav_btn("Standard Strain", "Culture Stock")
            nav_btn("Biological Indicator", "BI")
            st.markdown('<span class="sb-section">Reports</span>', unsafe_allow_html=True)
            nav_btn("Audit Trail", "Audit_Trail")
            nav_btn("Stock Opname", "Stock_Opname")
            # "User Management" is delegation-aware (an Active Delegate needs
            # it to reach the cut-down Pending Approval view) — "Settings" is
            # NOT one of the 5 delegated approval categories, so it stays
            # gated on the user's own native permission only.
            if has_permission_or_delegated("can_manage_users"):
                st.markdown('<span class="sb-section">Administration</span>', unsafe_allow_html=True)
                nav_btn("User Management", "User_Management")
                if has_permission("can_manage_users"):
                    nav_btn("Email Notification Settings", "⚙️ Settings")
        else:
            st.markdown('<span class="sb-section">Main</span>', unsafe_allow_html=True)
            nav_btn("Dashboard", "Dashboard")
            st.markdown('<span class="sb-section">Inventory</span>', unsafe_allow_html=True)
            nav_btn("Reagent", "Reagent")
            nav_btn("Standards", "Standards")
            nav_btn("Cell Culture", "Cell Culture")
            nav_btn("Storage Map", "Storage Map")
            st.markdown('<span class="sb-section">Planning & Reports</span>', unsafe_allow_html=True)
            nav_btn("Planning", "Planning")
            nav_btn("Documentation", "Documentation")
            nav_btn("Stock Opname", "Stock Opname")
            if has_permission("can_manage_users"):
                st.markdown('<span class="sb-section">Administration</span>', unsafe_allow_html=True)
                nav_btn("User Management", "User Management")
        st.markdown("<hr style='border:none;border-top:1px solid #F0F0F0;margin:8px 0;'>", unsafe_allow_html=True)
        if st.button("  Refresh Data", use_container_width=True, key=f"nav_{division}_refresh"):
            st.cache_data.clear(); st.rerun()
        if st.button("Log Out", use_container_width=True, key=f"nav_{division}_logout"):
            log_audit("LOGOUT", "Authentication", f"User logged out: {st.session_state.get('username', '-')}")
            for key in ["logged_in", "username", "role", "division", "full_name", "user_id", "user_role", "user_name", "menu"]:
                st.session_state.pop(key, None)
            st.session_state.logged_in = False
            st.rerun()
        st.markdown('<span class="sb-version">LIMS v2.0 ? PT Selatox Bio Pharma</span>', unsafe_allow_html=True)


def render_delegation_badge():
    """
    Small banner shown at the top of the main content area whenever the
    logged-in user currently has an Active delegation as a Delegate. No-op
    for every other session (non-delegate users, either division), so
    it's invisible unless relevant. Reads the per-rerun cache populated in
    render_sidebar_navigation() — never queries the DB itself — so it always
    reflects "right now" and disappears automatically the day after the
    delegation's end_date, with no manual step.
    """
    deleg = st.session_state.get("_active_deleg_as_delegate")
    if not deleg:
        return
    owner_label = deleg.get("owner_full_name") or deleg.get("owner_username", "")
    owner_role = str(deleg.get("owner_role_snapshot", "")).title()
    end_date = deleg.get("end_date", "")
    st.markdown(
        f"""
        <div style="background:#EEF2FF;border:1px solid #C7D2FE;border-radius:8px;
                    padding:8px 14px;margin:0 0 10px 0;font-size:13px;color:#3730A3;">
            🎭 Acting as Delegate for <b>{owner_label}</b> ({owner_role}) until {end_date}
        </div>
        """,
        unsafe_allow_html=True,
    )


def route_current_page():
    division = st.session_state.get("division", "QC1")
    menu = st.session_state.get("menu", "🏠 Dashboard" if division == "QC2" else "Dashboard")
    if division == "QC1":
        if menu == "Dashboard": dashboard_page()
        elif menu == "Reagent": reagent_page()
        elif menu == "Standards": standards_page()
        elif menu == "Cell Culture": cell_culture_page()
        elif menu == "Planning": planning_page()
        elif menu == "Storage Map": storage_map_page()
        elif menu == "Documentation": documentation_page()
        elif menu == "Stock Opname": stock_opname_page()
        elif menu == "User Management": user_management_page()
        else:
            st.session_state.menu = "Dashboard"; st.rerun()
    else:
        if menu == "🏠 Dashboard": dashboard_qc2_page()
        elif menu == "Media": media_page()
        elif menu == "Reagent": reagent_qc2_page()
        elif menu == "Culture Stock": culture_page()
        elif menu == "BI": bi_page()
        elif menu == "Audit_Trail": audit_trail_page()
        elif menu == "Stock_Opname": qc2_stock_opname_page()
        elif menu == "User_Management": user_management_page()
        elif menu == "⚙️ Settings": settings_qc2_page()
        else:
            st.session_state.menu = "🏠 Dashboard"; st.rerun()


# =============================================================================
#  NAVIGATION (unified)
# =============================================================================
if not st.session_state.logged_in:
    show_login_page()
else:
    render_sidebar_navigation()
    render_delegation_badge()
    route_current_page()